  1→package conn
  2→
  3→import (
  4→	"fmt"
  5→	"os"
  6→	"path/filepath"
  7→	"time"
  8→
  9→	"github.com/spf13/cobra"
 10→	"github.com/usenurge/nurgesh/cmd/cmdutil"
 11→	"github.com/usenurge/nurgesh/internal/account"
 12→	"github.com/usenurge/nurgesh/internal/connector"
 13→	"github.com/usenurge/nurgesh/internal/project"
 14→	"github.com/usenurge/nurgesh/internal/util"
 15→)
 16→
 17→var forceConnect bool
 18→
 19→func init() {
 20→	connectCmd.Flags().BoolVar(&forceConnect, "force", false, "Overwrite existing connection")
 21→}
 22→
 23→func checkExistingConnection(id string) (bool, string) {
 24→	if !project.IsNurgeProject(".") {
 25→		return false, ""
 26→	}
 27→	cfg, err := project.Load()
 28→	if err != nil {
 29→		return false, ""
 30→	}
 31→	cs, ok := cfg.Connectors[id]
 32→	if !ok || !cs.Connected {
 33→		return false, ""
 34→	}
 35→	return true, cs.Account
 36→}
 37→
 38→const connectLockTTL = 5 * time.Minute
 39→
 40→func acquireConnectLock(id string) (func(), error) {
 41→	lockDir := fmt.Sprintf(".nurge/connectors/%s", id)
 42→	if err := os.MkdirAll(lockDir, 0700); err != nil {
 43→		return nil, err
 44→	}
 45→	lockPath := filepath.Join(lockDir, ".connecting")
 46→	f, err := os.OpenFile(lockPath, os.O_CREATE|os.O_EXCL|os.O_WRONLY, 0600)
 47→	if err != nil {
 48→		if os.IsExist(err) {
 49→			// TTL-based stale lock detection: if lock file is older than 5 minutes, remove it and proceed
 50→			info, statErr := os.Stat(lockPath)
 51→			if statErr == nil && time.Since(info.ModTime()) > connectLockTTL {
 52→				fmt.Fprintf(os.Stderr, "  Removing stale lock file for %s (older than %s)\n", id, connectLockTTL)
 53→				os.Remove(lockPath)
 54→				// Retry creating the lock
 55→				f, err = os.OpenFile(lockPath, os.O_CREATE|os.O_EXCL|os.O_WRONLY, 0600)
 56→				if err != nil {
 57→					return nil, fmt.Errorf("%s connection lock could not be acquired after stale removal: %w", id, err)
 58→				}
 59→			} else {
 60→				return nil, fmt.Errorf("%s connection already in progress (remove %s if stale)", id, lockPath)
 61→			}
 62→		} else {
 63→			return nil, err
 64→		}
 65→	}
 66→	fmt.Fprintf(f, "%d", os.Getpid())
 67→	f.Close()
 68→	return func() { os.Remove(lockPath) }, nil
 69→}
 70→
 71→var connectCmd = &cobra.Command{
 72→	Use:   "connect <service>",
 73→	Short: "Connect a service (run `nurge connectors available` to see options)",
 74→	Args:  cobra.ExactArgs(1),
 75→	RunE: func(cmd *cobra.Command, args []string) error {
 76→		id := args[0]
 77→		if connected, existingAccount := checkExistingConnection(id); connected {
 78→			if !forceConnect {
 79→				fmt.Fprintf(os.Stderr, "  %s is already connected (%s)\n  Use --force to reconnect\n", id, existingAccount)
 80→				return fmt.Errorf("%s already connected, use --force to overwrite", id)
 81→			}
 82→			// Clean up old connection state before reconnecting
 83→			fmt.Fprintf(os.Stderr, "  Replacing existing %s connection (%s)...\n", id, existingAccount)
 84→			if id == "gmail" || id == "linkedin" || id == "hubspot" || id == "slack" {
 85→				af, authErr := account.LoadAuth()
 86→				if authErr == nil && af.Token != "" {
 87→					client := account.NewConvexClient(cmdutil.GetConvexURL())
 88→					providerMap := map[string]string{
 89→						"gmail":    "GOOGLE",
 90→						"linkedin": "LINKEDIN",
 91→						"hubspot":  "HUBSPOT",
 92→						"slack":    "SLACK",
 93→					}
 94→					if err := client.DisconnectProvider(af.Token, providerMap[id]); err != nil {
 95→						fmt.Fprintf(os.Stderr, "  warning: could not reset server connection: %v\n", err)
 96→					}
 97→				}
 98→			}
 99→			tokenDir := fmt.Sprintf(".nurge/connectors/%s", id)
100→			_ = os.RemoveAll(tokenDir)
101→		}
102→		cleanup, err := acquireConnectLock(id)
103→		if err != nil {
104→			return err
105→		}
106→		defer cleanup()
107→		switch id {
108→		case "gmail":
109→			return connectGmail()
110→		case "linkedin":
111→			return connectLinkedIn()
112→		case "hubspot":
113→			return connectHubSpot()
114→		case "slack":
115→			return connectSlack()
116→		default:
117→			registry, err := connector.LoadRegistry(projectLocalDefs)
118→			if err != nil {
119→				return fmt.Errorf("loading connector registry: %w", err)
120→			}
121→			var found *connector.ConnectorDef
122→			for i := range registry {
123→				if registry[i].ID == id {
124→					found = &registry[i]
125→					break
126→				}
127→			}
128→			if found == nil {
129→				return fmt.Errorf("unknown connector: %s\n  Run `nurge connectors available` to see all connectors", id)
130→			}
131→			c := connector.NewFromDef(*found, "")
132→			result, err := c.Connect(cmd.Context())
133→			if err != nil {
134→				return fmt.Errorf("connecting %s: %w", id, err)
135→			}
136→			if project.IsNurgeProject(".") {
137→				_ = project.SetConnector(id, found.Type, result.Account)
138→			}
139→			fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m %s connected (%s)\n", found.Name, result.Account)
140→		}
141→		return nil
142→	},
143→}
144→
145→func connectGmail() error {
146→	af, err := account.LoadAuth()
147→	if err != nil || af.Token == "" {
148→		return fmt.Errorf("not logged in. Run: nurge account login")
149→	}
150→
151→	client := account.NewConvexClient(cmdutil.GetConvexURL())
152→
153→	fmt.Fprintf(os.Stderr, "  Requesting Gmail connection...\n")
154→	resp, err := client.ConnectGmail(af.Token)
155→	if err != nil {
156→		return fmt.Errorf("connect failed: %w", err)
157→	}
158→
159→	if resp.AlreadyConnected {
160→		if resp.MaxReached {
161→			fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Max 2 Gmail accounts connected (%s)\n", resp.Email)
162→		} else {
163→			fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Gmail already connected (%s)\n", resp.Email)
164→		}
165→		if project.IsNurgeProject(".") {
166→			_ = project.SetConnector("gmail", "email", resp.Email)
167→		}
168→		return nil
169→	}
170→
171→	fmt.Fprintf(os.Stderr, "  Opening browser to connect Gmail...\n")
172→	if err := util.OpenBrowser(resp.URL); err != nil {
173→		fmt.Fprintf(os.Stderr, "  Could not open browser. Please visit:\n  %s\n", resp.URL)
174→	}
175→
176→	fmt.Fprintf(os.Stderr, "  Waiting for Gmail connection...")
177→	timeout := time.After(5 * time.Minute)
178→	ticker := time.NewTicker(2 * time.Second)
179→	defer ticker.Stop()
180→
181→	for {
182→		select {
183→		case <-timeout:
184→			fmt.Fprintf(os.Stderr, "\n")
185→			return fmt.Errorf("timed out after 5 minutes waiting for Gmail connection.\n  Run `nurge connect gmail` to try again")
186→		case <-ticker.C:
187→			status, err := client.ConnectionStatus(af.Token, "GOOGLE")
188→			if err != nil {
189→				continue
190→			}
191→			if status.Connected {
