412→// ── Send approved reply via existing Unipile path ───────────────────
413→
414→async function sendApprovedReply(
415→  ctx: ActionCtx,
416→  draftId: Id<"replyDrafts">,
417→  sendData: {
418→    userId: string;
419→    contactEmail: string;
420→    threadId: string;
421→    subject: string;
422→    body: string;
423→  }
424→): Promise<boolean> {
425→  // Prefer direct Gmail API (no Unipile dependency, no cost)
426→  const gmailAuth = await getAccessTokenForUser(ctx, sendData.userId);
427→  if (gmailAuth) {
428→    const result = await callGmailSend({
429→      accessToken: gmailAuth.accessToken,
430→      from: gmailAuth.email,
431→      to: sendData.contactEmail,
432→      subject: sendData.subject,
433→      body: sendData.body,
434→      threadId: sendData.threadId,
435→    });
436→
437→    if (result.ok) {
438→      await ctx.runMutation(internal.replyDrafts.markDraftSent, { draftId });
439→      return true;
440→    }
441→
442→    // If Gmail auth error, fall through to Unipile
443→    if (!result.authError) {
444→      console.error("Gmail send failed:", result.error);
445→      return false;
446→    }
447→    console.warn("Gmail auth failed, falling back to Unipile");
448→  }
449→
450→  // Fallback: Unipile (if Gmail credentials unavailable or auth expired)
451→  const unipileAccount = await ctx.runQuery(
452→    internal.sendApi.findUnipileAccount,
453→    { userId: sendData.userId, provider: "GOOGLE" }
454→  );
455→
456→  if (!unipileAccount || unipileAccount.status !== "connected") {
457→    console.error("No send path available: Gmail credentials expired and Unipile not connected");
458→    return false;
459→  }
460→
461→  const enrollment = await ctx.runQuery(
462→    internal.slack.findEnrollmentByThread,
463→    { userId: sendData.userId, threadId: sendData.threadId }
464→  );
465→
466→  const sendResult = await callUnipileSend({
467→    accountId: unipileAccount.unipileAccountId,
468→    to: sendData.contactEmail,
469→    subject: sendData.subject,
470→    body: sendData.body,
471→    replyTo: enrollment?.unipileThreadProviderId || undefined,
472→  });
473→
474→  if (sendResult.ok) {
475→    await ctx.runMutation(internal.replyDrafts.markDraftSent, { draftId });
476→    return true;
477→  }
478→
479→  console.error("Unipile send failed:", sendResult.error);
480→  return false;
481→}
