541→// ── Internal mutations ──────────────────────────────────────────────
542→
543→export const upsertSlackConnection = internalMutation({
544→  args: {
545→    userId: v.string(),
546→    teamId: v.string(),
547→    teamName: v.optional(v.string()),
548→    channelId: v.string(),
549→    channelName: v.optional(v.string()),
550→    encryptedBotToken: v.string(),
551→    botTokenIv: v.string(),
552→    scopes: v.optional(v.string()),
553→  },
554→  handler: async (ctx, args) => {
555→    const existing = await ctx.db
556→      .query("slackConnections")
557→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
558→      .collect();
559→
560→    const now = new Date().toISOString();
561→    const patch = {
562→      teamId: args.teamId,
563→      teamName: args.teamName,
564→      channelId: args.channelId,
565→      channelName: args.channelName,
566→      encryptedBotToken: args.encryptedBotToken,
567→      botTokenIv: args.botTokenIv,
568→      scopes: args.scopes,
569→      installedAt: now,
570→      lastUsedAt: now,
571→      lastErrorAt: undefined as string | undefined,
572→      lastError: undefined as string | undefined,
573→      consecutiveErrors: 0,
574→      status: "active",
575→    };
576→
577→    if (existing.length === 0) {
578→      await ctx.db.insert("slackConnections", {
579→        userId: args.userId,
580→        ...patch,
581→      });
582→      return;
583→    }
584→
585→    await ctx.db.patch(existing[0]._id, patch);
586→    // Revoke duplicates
587→    for (const duplicate of existing.slice(1)) {
588→      await ctx.db.patch(duplicate._id, { status: "revoked" });
589→    }
590→  },
591→});
592→
593→export const revokeSlackConnection = internalMutation({
594→  args: { userId: v.string() },
595→  handler: async (ctx, args) => {
596→    const existing = await ctx.db
597→      .query("slackConnections")
598→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
599→      .collect();
600→
601→    const now = new Date().toISOString();
602→    for (const conn of existing) {
603→      await ctx.db.patch(conn._id, {
604→        status: "revoked",
605→        lastUsedAt: now,
606→      });
607→    }
608→  },
609→});
610→
611→export const trackSlackSuccess = internalMutation({
612→  args: { userId: v.string() },
613→  handler: async (ctx, args) => {
614→    const conn = await ctx.db
615→      .query("slackConnections")
616→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
617→      .first();
618→    if (!conn || conn.status !== "active") return;
619→
620→    await ctx.db.patch(conn._id, {
621→      lastUsedAt: new Date().toISOString(),
622→      consecutiveErrors: 0,
623→    });
624→  },
625→});
626→
627→export const trackSlackError = internalMutation({
628→  args: { userId: v.string(), error: v.string() },
629→  handler: async (ctx, args) => {
630→    const conn = await ctx.db
631→      .query("slackConnections")
632→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
633→      .first();
634→    if (!conn) return;
635→
636→    const errors = (conn.consecutiveErrors || 0) + 1;
637→    const now = new Date().toISOString();
638→
639→    if (errors >= MAX_CONSECUTIVE_ERRORS) {
640→      // Auto-revoke after too many consecutive failures
641→      await ctx.db.patch(conn._id, {
642→        status: "error",
643→        lastErrorAt: now,
644→        lastError: `Auto-disabled after ${errors} consecutive errors: ${args.error}`,
645→        consecutiveErrors: errors,
646→        lastUsedAt: now,
647→      });
648→      console.error(
649→        `Slack connection auto-disabled for user ${args.userId} after ${errors} errors`
650→      );
651→    } else {
652→      await ctx.db.patch(conn._id, {
653→        lastErrorAt: now,
654→        lastError: args.error,
655→        consecutiveErrors: errors,
656→        lastUsedAt: now,
657→      });
658→    }
659→  },
660→});
