397→func (c *ConvexClient) enrichPost(token, path string, payload interface{}) ([]byte, error) {
398→	body, err := json.Marshal(payload)
399→	if err != nil {
400→		return nil, fmt.Errorf("marshaling request: %w", err)
401→	}
402→
403→	var resp *http.Response
404→	var lastErr error
405→	for attempt := 0; attempt < 3; attempt++ {
406→		if attempt > 0 {
407→			time.Sleep(time.Duration(1<<attempt) * time.Second)
408→		}
409→		enrichLimiter.wait()
410→
411→		httpReq, err := http.NewRequest("POST", c.baseURL+path, bytes.NewReader(body))
412→		if err != nil {
413→			return nil, fmt.Errorf("creating request: %w", err)
414→		}
415→		httpReq.Header.Set("Content-Type", "application/json")
416→		httpReq.Header.Set("Authorization", "Bearer "+token)
417→
418→		resp, lastErr = c.enrichClient.Do(httpReq)
419→		if lastErr == nil && resp.StatusCode < 500 {
420→			break
421→		}
422→		if resp != nil {
423→			resp.Body.Close()
424→		}
425→	}
426→	if lastErr != nil {
427→		return nil, fmt.Errorf("calling %s: %w", path, lastErr)
428→	}
429→	defer resp.Body.Close()
430→
431→	data, err := io.ReadAll(io.LimitReader(resp.Body, 50*1024*1024))
432→	if err != nil {
433→		return nil, fmt.Errorf("reading response: %w", err)
434→	}
435→
436→	if resp.StatusCode != 200 {
437→		var errResp struct {
438→			Error string `json:"error"`
439→		}
440→		json.Unmarshal(data, &errResp)
441→		if errResp.Error != "" {
442→			return nil, fmt.Errorf("%s", errResp.Error)
443→		}
444→		return nil, fmt.Errorf("HTTP %d: %s", resp.StatusCode, string(data))
445→	}
446→
447→	return data, nil
448→}
