12→
13→// GenericConnector implements Connector backed by a YAMLConnector definition.
14→type GenericConnector struct {
15→	def         *YAMLConnector
16→	credentials string // optional override path (e.g. --credentials flag)
17→}
18→
19→// saveToken writes an OAuth2 token to disk with restricted permissions.
20→func saveToken(path string, token *oauth2.Token) error {
21→	f, err := os.OpenFile(path, os.O_RDWR|os.O_CREATE|os.O_TRUNC, 0600)
22→	if err != nil {
23→		return err
24→	}
25→	defer f.Close()
26→	return json.NewEncoder(f).Encode(token)
27→}
28→
29→// saveTokenAtomic writes an OAuth2 token to disk atomically via a temp file + rename.
30→func saveTokenAtomic(path string, token *oauth2.Token) error {
31→	data, err := json.Marshal(token)
32→	if err != nil {
33→		return err
34→	}
35→	return securefile.WriteAtomic(path, data, 0600)
36→}
37→
38→func (g *GenericConnector) ID() string   { return g.def.ID }
39→func (g *GenericConnector) Name() string { return g.def.Name }
40→func (g *GenericConnector) Type() string { return g.def.Type }
41→
42→func (g *GenericConnector) Connect(ctx context.Context) (*Result, error) {
43→	switch g.def.Auth.Method {
44→	case "oauth2":
45→		return g.connectOAuth2(ctx)
46→	case "api_key":
47→		return g.connectAPIKey(ctx)
48→	case "basic":
49→		return g.connectBasic(ctx)
50→	case "webhook":
51→		return g.connectWebhook(ctx)
52→	default:
53→		return nil, fmt.Errorf("unsupported auth method: %s", g.def.Auth.Method)
54→	}
55→}
