 49→// connectorsAvailableCmd lists ALL known connectors grouped by type, with connection status.
 50→var connectorsAvailableCmd = &cobra.Command{
 51→	Use:   "available",
 52→	Short: "List all available connectors (bundled + project-local)",
 53→	RunE: func(cmd *cobra.Command, args []string) error {
 54→		// Config is optional — if not in a project dir, just omit status.
 55→		cfg, _ := project.Load()
 56→
 57→		registry, err := connector.LoadRegistry(projectLocalDefs)
 58→		if err != nil {
 59→			return fmt.Errorf("loading registry: %w", err)
 60→		}
 61→
 62→		// Group by type.
 63→		groups := map[string][]connector.ConnectorDef{}
 64→		order := []string{}
 65→		seen := map[string]bool{}
 66→		for _, def := range registry {
 67→			if !seen[def.Type] {
 68→				seen[def.Type] = true
 69→				order = append(order, def.Type)
 70→			}
 71→			groups[def.Type] = append(groups[def.Type], def)
 72→		}
 73→
 74→		for _, typ := range order {
 75→			// Capitalise the type heading.
 76→			heading := strings.ToUpper(typ[:1]) + typ[1:]
 77→			fmt.Printf("  %s\n", heading)
 78→			for _, def := range groups[typ] {
 79→				requiredMark := ""
 80→				if def.Required {
 81→					requiredMark = " *"
 82→				}
 83→				statusSuffix := ""
 84→				if cfg != nil {
 85→					if cs, ok := cfg.Connectors[def.ID]; ok && cs.Connected {
 86→						statusSuffix = fmt.Sprintf(" (connected: %s)", cs.Account)
 87→					}
 88→				}
 89→				fmt.Printf("    %-15s %-20s%s%s\n", def.ID, def.Name, requiredMark, statusSuffix)
 90→			}
 91→		}
 92→
 93→		return nil
 94→	},
 95→}
