import { v } from "convex/values";
import { internalAction, internalMutation } from "./_generated/server";
import { internal } from "./_generated/api";
import { generateId } from "./helpers";

// Shared Unipile send helper — used by both cron dispatcher and sync httpAction
export async function callUnipileSend(args: {
  accountId: string;
  to: string;
  subject: string;
  body: string;
  replyTo?: string;
}): Promise<
  | { ok: true; messageId: string; providerId: string }
  | { ok: false; error: string; authError: boolean }
> {
  const apiKey = process.env.UNIPILE_API_KEY;
  const apiUrl = process.env.UNIPILE_API_URL;
  if (!apiKey || !apiUrl) {
    return { ok: false, error: "Unipile API key or URL not configured", authError: false };
  }

  const payload: Record<string, any> = {
    account_id: args.accountId,
    to: [{ identifier: args.to }],
    subject: args.subject,
    body: args.body,
  };

  if (args.replyTo) {
    payload.reply_to = args.replyTo;
  }

  // Add 30s timeout to Unipile fetch call
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), 30000);

  let resp: Response;
  try {
    resp = await fetch(`${apiUrl}/api/v1/emails`, {
      method: "POST",
      headers: {
        "X-API-KEY": apiKey,
        "Content-Type": "application/json",
      },
      body: JSON.stringify(payload),
      signal: controller.signal,
    });
  } catch (fetchError: any) {
    clearTimeout(timeoutId);
    if (fetchError.name === "AbortError") {
      return { ok: false, error: "Unipile API request timed out (30s)", authError: false };
    }
    return { ok: false, error: `Unipile API fetch error: ${fetchError.message}`, authError: false };
  }
  clearTimeout(timeoutId);

  if (!resp.ok) {
    const errorText = await resp.text();
    const isAuth = resp.status === 401 || resp.status === 403;
    return {
      ok: false,
      error: isAuth ? `Auth error: ${errorText}` : `Unipile API error ${resp.status}: ${errorText}`,
      authError: isAuth,
    };
  }

  const result = await resp.json();
  return {
    ok: true,
    messageId: result.id || "",
    providerId: JSON.stringify(result.provider_id || ""),
  };
}

// Send via Unipile — called by cron dispatcher
export const sendViaUnipile = internalAction({
  args: {
    userId: v.string(),
    taskId: v.string(), // externalId of follow_up_task
    accountId: v.string(), // Unipile account ID
    to: v.string(),
    subject: v.string(),
    body: v.string(),
    replyTo: v.optional(v.string()), // provider_id for threading
  },
  handler: async (ctx, args) => {
    const result = await callUnipileSend({
      accountId: args.accountId,
      to: args.to,
      subject: args.subject,
      body: args.body,
      replyTo: args.replyTo,
    });

    if (!result.ok) {
      if (result.authError) {
        await ctx.runMutation(internal.send.recordAuthFailure, {
          userId: args.userId,
          taskId: args.taskId,
          mailboxId: "",
          error: result.error,
        });
      } else {
        await ctx.runMutation(internal.send.recordSendFailure, {
          userId: args.userId,
          taskId: args.taskId,
          error: result.error,
        });
      }
      return { ok: false, error: result.error };
    }

    await ctx.runMutation(internal.send.recordSendSuccess, {
      userId: args.userId,
      taskId: args.taskId,
      unipileMessageId: result.messageId,
      providerId: result.providerId,
    });

    return { ok: true, messageId: result.messageId, providerId: result.providerId };
  },
});

// Record successful send — updates task, creates send event, advances enrollment
export const recordSendSuccess = internalMutation({
  args: {
    userId: v.string(),
    taskId: v.string(),
    unipileMessageId: v.string(),
    providerId: v.string(),
  },
  handler: async (ctx, args) => {
    const task = await ctx.db
      .query("followUpTasks")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
      .first();

    if (!task) return;

    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    let version = (syncState?.lastSyncVersion ?? 0) + 1;

    // Update task
    await ctx.db.patch(task._id, {
      status: "completed",
      sendStatus: "sent",
      completedAt: new Date().toISOString(),
      unipileMessageId: args.unipileMessageId,
      providerId: args.providerId,
      syncVersion: version,
    });

    // Create send event
    const sendEventId = generateId("mse");
    await ctx.db.insert("mailboxSendEvents", {
      externalId: sendEventId,
      mailboxId: task.mailboxId,
      sendType: task.sendType,
      sentAt: new Date().toISOString(),
      taskId: args.taskId,
      enrollmentId: task.enrollmentId,
      unipileMessageId: args.unipileMessageId,
      providerId: args.providerId,
      syncVersion: version,
      userId: args.userId,
    });

    // Advance enrollment
    const enrollment = await ctx.db
      .query("sequenceEnrollments")
      .withIndex("by_external_id", (q) => q.eq("externalId", task.enrollmentId))
      .first();

    if (enrollment) {
      version++;
      const newStep = task.stepNumber;
      const isComplete = newStep >= enrollment.totalSteps;

      await ctx.db.patch(enrollment._id, {
        currentStep: newStep,
        lastSentAt: new Date().toISOString(),
        lastMessageId: args.unipileMessageId,
        status: isComplete ? "completed" : enrollment.status,
        nextDueAt: isComplete ? "" : enrollment.nextDueAt,
        unipileThreadProviderId: args.providerId || enrollment.unipileThreadProviderId,
        syncVersion: version,
      });

      // Mark draft as sent
      const draft = await ctx.db
        .query("sequenceDrafts")
        .withIndex("by_task", (q) => q.eq("taskId", args.taskId))
        .first();
      if (draft) {
        await ctx.db.patch(draft._id, {
          status: "sent",
          syncVersion: version,
        });
      }
    }

    // Update sync state
    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
    } else {
      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
    }
  },
});

// Record send failure — increment attempt count, set error
export const recordSendFailure = internalMutation({
  args: {
    userId: v.string(),
    taskId: v.string(),
    error: v.string(),
  },
  handler: async (ctx, args) => {
    const task = await ctx.db
      .query("followUpTasks")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
      .first();

    if (!task) return;

    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    const version = (syncState?.lastSyncVersion ?? 0) + 1;

    const newAttemptCount = task.attemptCount + 1;

    // Configurable max retries per send type
    const maxRetriesMap: Record<string, number> = {
      first_touch: 5,
      follow_up: 5,
      reply: 3,  // Replies are more time-sensitive, fewer retries
    };
    const maxRetries = maxRetriesMap[task.sendType] || 5;

    // Check max retry age: if task has been retrying for > 7 days, give up
    const dueAt = new Date(task.dueAt).getTime();
    const now = Date.now();
    const maxRetryAgeMs = 7 * 24 * 60 * 60 * 1000; // 7 days
    const isTooOld = now - dueAt > maxRetryAgeMs;

    // Also check stale window (48 hours past due) as original logic
    const staleWindowMs = 48 * 60 * 60 * 1000;
    const isStale = now - dueAt > staleWindowMs;

    const isFailed = newAttemptCount >= maxRetries || isStale || isTooOld;

    await ctx.db.patch(task._id, {
      sendStatus: isFailed ? "failed" : "pending", // back to pending for retry
      lastAttemptAt: new Date().toISOString(),
      lastError: args.error,
      attemptCount: newAttemptCount,
      status: isFailed ? "canceled" : task.status,
      canceledReason: isFailed
        ? isTooOld
          ? "stale: past 7-day retry window"
          : isStale
            ? "stale: past 48h window"
            : `max retries (${maxRetries}) exceeded`
        : task.canceledReason,
      syncVersion: version,
    });

    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
    } else {
      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
    }
  },
});

// Record auth failure — mark mailbox as auth_expired, pause enrollment
export const recordAuthFailure = internalMutation({
  args: {
    userId: v.string(),
    taskId: v.string(),
    mailboxId: v.string(),
    error: v.string(),
  },
  handler: async (ctx, args) => {
    const task = await ctx.db
      .query("followUpTasks")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
      .first();

    if (!task) return;

    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    let version = (syncState?.lastSyncVersion ?? 0) + 1;

    // Mark task as failed (don't retry auth errors)
    await ctx.db.patch(task._id, {
      sendStatus: "failed",
      lastError: args.error,
      lastAttemptAt: new Date().toISOString(),
      syncVersion: version,
    });

    // Mark mailbox as auth_expired
    const mailbox = await ctx.db
      .query("mailboxes")
      .withIndex("by_external_id", (q) => q.eq("externalId", task.mailboxId))
      .first();

    if (mailbox) {
      version++;
      await ctx.db.patch(mailbox._id, {
        status: "auth_expired",
        syncVersion: version,
      });
    }

    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
    } else {
      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
    }
  },
});

