 11→  withinSendWindow,
 12→} from "./helpers";
 13→
 14→// Payload interfaces for send API
 15→interface SequenceStep {
 16→  stepNumber?: number;
 17→  stepName?: string;
 18→  sendType?: string;
 19→  delayDays?: number;
 20→  subject?: string;
 21→  body?: string;
 22→}
 23→
 24→interface SequencePayload {
 25→  sequenceName: string;
 26→  campaignName?: string;
 27→  mailboxId?: string;
 28→  contactName?: string;
 29→  steps?: SequenceStep[];
 30→}
 31→
 32→interface SendPayload {
 33→  to?: string;
 34→  subject?: string;
 35→  body?: string;
 36→  sendType?: string;
 37→  sync?: boolean;
 38→  taskId?: string;
 39→  sequence?: SequencePayload;
 40→}
 41→
 42→// POST /api/send-email — single endpoint for all CLI-initiated sends
 43→//
 44→// Sync sends (sync: true): calls Unipile immediately, returns result.
 45→// Async sends (sync: false): creates task with pending status, cron picks it up.
 46→// Sequence sends: creates enrollment + future follow-up tasks + drafts.
 47→export const sendEmail = httpAction(async (ctx, request) => {
 48→  try {
 49→    const payload = await request.json();
 50→
 51→    // --- Auth ---
 52→    const authHeader = request.headers.get("Authorization");
 53→    if (!authHeader || !authHeader.startsWith("Bearer ")) {
 54→      return jsonResponse({ ok: false, error: "Missing auth token" }, 401);
 55→    }
 56→    const token = authHeader.slice(7);
 57→
 58→    const user = await ctx.runQuery(internal.sendApi.findUserByToken, { token });
 59→    if (!user) {
 60→      return jsonResponse({ ok: false, error: "Invalid auth token" }, 401);
 61→    }
 62→    const userId = user._id;
 63→
 64→    // --- Validate required fields ---
 65→    const { to, subject, body, sendType, sync, taskId, sequence } = payload;
 66→
 67→    // If taskId is provided, we're sending an existing task
 68→    if (taskId) {
 69→      return await handleExistingTask(ctx, userId, taskId, payload);
 70→    }
 71→
 72→    if (!to || !subject || !body) {
 73→      return jsonResponse({ ok: false, error: "to, subject, and body are required" }, 400);
 74→    }
 75→
 76→    // Validate email format
 77→    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
 78→    if (!emailRegex.test(to)) {
 79→      return jsonResponse({ ok: false, error: "Invalid email format for 'to' field" }, 400);
 80→    }
 81→
 82→    // --- Look up Unipile account ---
 83→    const unipileAccount = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
 84→      userId,
 85→      provider: "GOOGLE",
 86→    });
 87→    if (!unipileAccount) {
 88→      return jsonResponse({ ok: false, error: "No connected email account. Run: nurge connect gmail" }, 400);
 89→    }
 90→    if (unipileAccount.status !== "connected") {
 91→      const msg = unipileAccount.status === "disconnected"
 92→        ? "Email account disconnected. Reconnect via nurge connect gmail"
 93→        : "Email account auth expired. Re-authenticate via nurge connect gmail";
 94→      return jsonResponse({ ok: false, error: msg }, 400);
 95→    }
 96→
 97→    // --- Resolve mailbox ---
 98→    const mailboxId = sequence?.mailboxId || null;
 99→    const mailbox = mailboxId
100→      ? await ctx.runQuery(internal.sendApi.findMailboxById, { externalId: mailboxId })
101→      : await ctx.runQuery(internal.sendApi.findActiveMailbox, { userId });
102→
103→    if (!mailbox) {
104→      return jsonResponse({ ok: false, error: "No active mailbox found" }, 400);
105→    }
106→    if (mailbox.status === "auth_expired") {
107→      return jsonResponse({ ok: false, error: "Mailbox auth expired. Re-authenticate via nurge connect gmail" }, 400);
108→    }
109→
110→    // --- Suppression check ---
111→    const suppression = await ctx.runQuery(internal.sendApi.checkSuppression, { userId, email: to });
112→    if (suppression.suppressed) {
113→      return jsonResponse({ ok: false, error: `Contact suppressed: ${suppression.reason}` }, 400);
114→    }
115→
116→    // --- Send window + daily cap ---
117→    const effectiveSendType = sendType || "first_touch";
118→    if (!withinSendWindow(mailbox.sendWindowStartHour, mailbox.sendWindowEndHour, mailbox.sendWindowTimezone)) {
119→      if (sync) {
120→        return jsonResponse({ ok: false, error: "Outside send window" }, 400);
121→      }
122→      // Async: task will be picked up when window opens
123→    }
124→
125→    const today = todayInTimezone(mailbox.sendWindowTimezone);
126→    const sendCount = await ctx.runQuery(internal.sendApi.countSends, {
127→      mailboxId: mailbox.externalId,
128→      sendType: effectiveSendType,
129→      day: today,
130→    });
131→    const capMap: Record<string, number> = {
132→      first_touch: mailbox.firstTouchDailyCap,
133→      follow_up: mailbox.followUpDailyCap,
134→      reply: mailbox.replyDailyCap,
135→    };
136→    const cap = capMap[effectiveSendType] || 0;
137→    if (cap > 0 && sendCount >= cap) {
138→      if (sync) {
139→        return jsonResponse({ ok: false, error: `Daily ${effectiveSendType} cap reached (${cap})` }, 400);
140→      }
141→    }
142→
143→    // --- Generate IDs ---
144→    const now = new Date().toISOString();
145→    const taskExternalId = generateId("task");
146→    const enrollmentExternalId = sequence ? generateId("enr") : "";
147→
148→    // --- Create enrollment + future tasks if sequence ---
149→    if (sequence) {
150→      // Check for existing active enrollment
151→      const existingEnrollment = await ctx.runQuery(internal.sendApi.findActiveEnrollment, {
152→        userId,
153→        mailboxId: mailbox.externalId,
154→        contactEmail: to,
155→      });
156→      if (existingEnrollment) {
157→        return jsonResponse({
158→          ok: false,
159→          error: `${to} already has an active sequence enrollment (${existingEnrollment.externalId})`,
160→        }, 400);
161→      }
162→
163→      try {
164→        await ctx.runMutation(internal.sendApi.createSendEnrollment, {
165→          userId,
166→          enrollment: {
167→            externalId: enrollmentExternalId,
168→            sequenceName: sequence.sequenceName,
169→            campaignName: sequence.campaignName || "",
170→            mailboxId: mailbox.externalId,
171→            contactEmail: to,
172→            contactName: sequence.contactName || "",
173→            subject,
174→            currentStep: 1,
175→            totalSteps: 1 + (sequence.steps?.length || 0),
176→            initialBody: body,
177→            unipileAccountId: unipileAccount.unipileAccountId,
178→          },
179→          firstTask: {
180→            externalId: taskExternalId,
181→            stepNumber: 1,
182→            stepName: "first_touch",
183→            sendType: "first_touch",
184→            dueAt: now,
185→            subject,
186→            body,
187→            contactEmail: to,
188→            mailboxId: mailbox.externalId,
189→          },
190→          futureSteps: (sequence.steps || []).map((step: SequenceStep, i: number) => {
191→            const stepTaskId = `${generateId("task")}-s${step.stepNumber || i + 2}`;
192→            const draftId = `${generateId("draft")}-s${step.stepNumber || i + 2}`;
193→            // Clamp negative delayDays to 0
194→            const delayDays = Math.max(0, step.delayDays ?? 3);
195→            const dueDate = new Date(Date.now() + delayDays * 86400000).toISOString();
196→            return {
197→              task: {
198→                externalId: stepTaskId,
199→                stepNumber: step.stepNumber || i + 2,
200→                stepName: step.stepName || `follow_up_${i + 1}`,
201→                sendType: step.sendType || "follow_up",
202→                dueAt: dueDate,
203→                subject: step.subject || subject,
204→                body: step.body || "",
205→                contactEmail: to,
206→                mailboxId: mailbox.externalId,
207→              },
208→              draft: {
209→                externalId: draftId,
210→                taskId: stepTaskId,
211→                stepNumber: step.stepNumber || i + 2,
212→                subject: step.subject || subject,
213→                body: step.body || "",
214→                channel: "email",
215→              },
216→            };
217→          }),
218→        });
219→      } catch (seqError: unknown) {
220→        const seqMessage = seqError instanceof Error ? seqError.message : String(seqError);
221→        console.error("Sequence creation failed:", seqMessage);
222→        // Clean up partial enrollment if creation failed partway through.
223→        // Note: Convex mutations are atomic, so if createSendEnrollment threw,
224→        // nothing was committed. This catch is for errors in the action layer.
225→        return jsonResponse({ ok: false, error: "Failed to create sequence enrollment" }, 500);
226→      }
227→    } else {
228→      // One-off send: create standalone task
229→      await ctx.runMutation(internal.sendApi.createStandaloneTask, {
230→        userId,
231→        task: {
232→          externalId: taskExternalId,
233→          enrollmentId: "",
234→          mailboxId: mailbox.externalId,
235→          contactEmail: to,
236→          subject,
237→          body,
238→          stepNumber: 1,
239→          sendType: effectiveSendType,
240→          dueAt: now,
241→        },
242→      });
243→    }
244→
245→    // --- Sync: send now ---
246→    if (sync) {
247→      const sendResult = await callUnipileSend({
248→        accountId: unipileAccount.unipileAccountId,
249→        to,
250→        subject,
251→        body,
252→      });
253→
254→      if (!sendResult.ok) {
255→        await ctx.runMutation(internal.sendApi.markTaskFailed, {
256→          userId,
257→          taskId: taskExternalId,
258→          error: sendResult.error,
259→          authError: sendResult.authError,
260→          mailboxId: mailbox.externalId,
261→        });
262→        return jsonResponse({ ok: false, error: sendResult.error }, 502);
263→      }
264→
265→      await ctx.runMutation(internal.sendApi.markTaskSent, {
266→        userId,
267→        taskId: taskExternalId,
268→        enrollmentId: enrollmentExternalId,
269→        mailboxId: mailbox.externalId,
270→        sendType: effectiveSendType,
271→        unipileMessageId: sendResult.messageId,
272→        providerId: sendResult.providerId,
273→      });
274→
275→      return jsonResponse({
276→        ok: true,
277→        messageId: sendResult.messageId,
278→        providerId: sendResult.providerId,
279→        taskId: taskExternalId,
280→        enrollmentId: enrollmentExternalId || undefined,
281→      });
282→    }
283→
284→    // --- Async: return queued ---
285→    return jsonResponse({
286→      ok: true,
287→      queued: true,
288→      taskId: taskExternalId,
289→      enrollmentId: enrollmentExternalId || undefined,
290→    });
291→  } catch (error: unknown) {
292→    const message = error instanceof Error ? error.message : String(error);
293→    const stack = error instanceof Error ? error.stack : undefined;
294→    console.error("sendEmail error:", message, stack);
295→    // Don't leak internal details to the client
296→    return jsonResponse({ ok: false, error: "Internal error" }, 500);
297→  }
298→});
