300→// Handle sending an existing task (--task-id flow)
301→async function handleExistingTask(ctx: ActionCtx, userId: string, taskId: string, payload: SendPayload) {
302→  const task = await ctx.runQuery(internal.sendApi.findTask, { externalId: taskId });
303→  if (!task) {
304→    return jsonResponse({ ok: false, error: `Task ${taskId} not found` }, 404);
305→  }
306→  if (task.userId !== userId) {
307→    return jsonResponse({ ok: false, error: "Task does not belong to this user" }, 403);
308→  }
309→  if (task.status !== "open") {
310→    return jsonResponse({ ok: false, error: `Task is ${task.status}, not open` }, 400);
311→  }
312→  if (task.sendStatus === "sent") {
313→    return jsonResponse({ ok: false, error: "Task already sent" }, 400);
314→  }
315→
316→  // Resolve Unipile account
317→  const unipileAccount = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
318→    userId,
319→    provider: "GOOGLE",
320→  });
321→  if (!unipileAccount) {
322→    return jsonResponse({ ok: false, error: "No connected email account" }, 400);
323→  }
324→  if (unipileAccount.status !== "connected") {
325→    const msg = unipileAccount.status === "disconnected"
326→      ? "Email account disconnected. Reconnect via nurge connect gmail"
327→      : "Email account auth expired. Re-authenticate via nurge connect gmail";
328→    return jsonResponse({ ok: false, error: msg }, 400);
329→  }
330→
331→  // Use payload overrides or task defaults
332→  const to = payload.to || task.contactEmail;
333→  const subject = payload.subject || task.subject || "";
334→  const body = payload.body || task.body || "";
335→
336→  // Look up draft for latest content
337→  const draft = await ctx.runQuery(internal.sendApi.findDraft, { taskId });
338→  const finalSubject = subject || draft?.subject || "";
339→  const finalBody = body || draft?.body || "";
340→
341→  if (!finalSubject || !finalBody) {
342→    return jsonResponse({ ok: false, error: "No subject or body available for this task" }, 400);
343→  }
344→
345→  // Get enrollment for threading
346→  const enrollment = task.enrollmentId
347→    ? await ctx.runQuery(internal.sendApi.findEnrollment, { externalId: task.enrollmentId })
348→    : null;
349→
350→  const replyTo = enrollment?.unipileThreadProviderId || undefined;
351→
352→  const sendResult = await callUnipileSend({
353→    accountId: unipileAccount.unipileAccountId,
354→    to,
355→    subject: finalSubject,
356→    body: finalBody,
357→    replyTo,
358→  });
359→
360→  if (!sendResult.ok) {
361→    await ctx.runMutation(internal.sendApi.markTaskFailed, {
362→      userId,
363→      taskId,
364→      error: sendResult.error,
365→      authError: sendResult.authError,
366→      mailboxId: task.mailboxId,
367→    });
368→    return jsonResponse({ ok: false, error: sendResult.error }, 502);
369→  }
370→
371→  await ctx.runMutation(internal.sendApi.markTaskSent, {
372→    userId,
373→    taskId,
374→    enrollmentId: task.enrollmentId,
375→    mailboxId: task.mailboxId,
376→    sendType: task.sendType,
377→    unipileMessageId: sendResult.messageId,
378→    providerId: sendResult.providerId,
379→  });
380→
381→  return jsonResponse({
382→    ok: true,
383→    messageId: sendResult.messageId,
384→    providerId: sendResult.providerId,
385→    taskId,
386→    enrollmentId: task.enrollmentId || undefined,
387→  });
388→}
