601→
602→    // Create enrollment
603→    await ctx.db.insert("sequenceEnrollments", {
604→      externalId: args.enrollment.externalId,
605→      sequenceName: args.enrollment.sequenceName,
606→      campaignName: args.enrollment.campaignName,
