612→      totalSteps: args.enrollment.totalSteps,
613→      initialBody: args.enrollment.initialBody,
614→      unipileAccountId: args.enrollment.unipileAccountId,
615→      status: "active",
616→      statusReason: "",
617→      replyState: "",
618→      lastSentAt: new Date().toISOString(),
619→      nextDueAt: args.firstTask.dueAt,
620→      syncVersion: version,
621→      userId: args.userId,
622→    });
623→
624→    // Create first task
625→    await ctx.db.insert("followUpTasks", {
626→      externalId: args.firstTask.externalId,
627→      enrollmentId: args.enrollment.externalId,
628→      mailboxId: args.firstTask.mailboxId,
629→      contactEmail: args.firstTask.contactEmail,
630→      subject: args.firstTask.subject,
631→      body: args.firstTask.body,
632→      threadId: "",
633→      stepNumber: args.firstTask.stepNumber,
