641→      userId: args.userId,
642→    });
643→
644→    // Create future tasks + drafts
645→    for (const step of args.futureSteps) {
646→      await ctx.db.insert("followUpTasks", {
647→        externalId: step.task.externalId,
648→        enrollmentId: args.enrollment.externalId,
649→        mailboxId: step.task.mailboxId,
650→        contactEmail: step.task.contactEmail,
651→        subject: step.task.subject,
652→        body: step.task.body,
653→        threadId: "",
654→        stepNumber: step.task.stepNumber,
655→        stepName: step.task.stepName,
656→        sendType: step.task.sendType,
657→        status: "open",
658→        sendStatus: "pending",
659→        dueAt: step.task.dueAt,
660→        attemptCount: 0,
661→        syncVersion: version,
662→        userId: args.userId,
663→      });
664→
665→      await ctx.db.insert("sequenceDrafts", {
666→        externalId: step.draft.externalId,
667→        enrollmentId: args.enrollment.externalId,
668→        taskId: step.draft.taskId,
669→        stepNumber: step.draft.stepNumber,
670→        subject: step.draft.subject,
671→        body: step.draft.body,
672→        channel: step.draft.channel,
673→        status: "pending",
674→        syncVersion: version,
675→        userId: args.userId,
676→      });
677→    }
