699→      .query("followUpTasks")
700→      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
701→      .first();
702→    if (!task) return;
703→
704→    const syncState = await ctx.db
705→      .query("syncState")
706→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
707→      .first();
708→    let version = (syncState?.lastSyncVersion ?? 0) + 1;
709→
710→    // Update task
711→    await ctx.db.patch(task._id, {
712→      status: "completed",
713→      sendStatus: "sent",
714→      completedAt: new Date().toISOString(),
715→      unipileMessageId: args.unipileMessageId,
716→      providerId: args.providerId,
717→      syncVersion: version,
718→    });
719→
720→    // Create send event
721→    const sendEventId = generateId("mse");
722→    await ctx.db.insert("mailboxSendEvents", {
