import { v } from "convex/values";
import { httpAction, internalQuery, internalMutation } from "./_generated/server";
import type { ActionCtx } from "./_generated/server";
import { internal } from "./_generated/api";
import { callUnipileSend } from "./send";
import {
  generateId,
  isSuppressed,
  countSendsForDay,
  todayInTimezone,
  withinSendWindow,
} from "./helpers";

// Payload interfaces for send API
interface SequenceStep {
  stepNumber?: number;
  stepName?: string;
  sendType?: string;
  delayDays?: number;
  subject?: string;
  body?: string;
}

interface SequencePayload {
  sequenceName: string;
  campaignName?: string;
  mailboxId?: string;
  contactName?: string;
  steps?: SequenceStep[];
}

interface SendPayload {
  to?: string;
  subject?: string;
  body?: string;
  sendType?: string;
  sync?: boolean;
  taskId?: string;
  sequence?: SequencePayload;
}

// POST /api/send-email — single endpoint for all CLI-initiated sends
//
// Sync sends (sync: true): calls Unipile immediately, returns result.
// Async sends (sync: false): creates task with pending status, cron picks it up.
// Sequence sends: creates enrollment + future follow-up tasks + drafts.
export const sendEmail = httpAction(async (ctx, request) => {
  try {
    const payload = await request.json();

    // --- Auth ---
    const authHeader = request.headers.get("Authorization");
    if (!authHeader || !authHeader.startsWith("Bearer ")) {
      return jsonResponse({ ok: false, error: "Missing auth token" }, 401);
    }
    const token = authHeader.slice(7);

    const user = await ctx.runQuery(internal.sendApi.findUserByToken, { token });
    if (!user) {
      return jsonResponse({ ok: false, error: "Invalid auth token" }, 401);
    }
    const userId = user._id;

    // --- Validate required fields ---
    const { to, subject, body, sendType, sync, taskId, sequence } = payload;

    // If taskId is provided, we're sending an existing task
    if (taskId) {
      return await handleExistingTask(ctx, userId, taskId, payload);
    }

    if (!to || !subject || !body) {
      return jsonResponse({ ok: false, error: "to, subject, and body are required" }, 400);
    }

    // Validate email format
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(to)) {
      return jsonResponse({ ok: false, error: "Invalid email format for 'to' field" }, 400);
    }

    // --- Look up Unipile account ---
    const unipileAccount = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
      userId,
      provider: "GOOGLE",
    });
    if (!unipileAccount) {
      return jsonResponse({ ok: false, error: "No connected email account. Run: nurge connect gmail" }, 400);
    }
    if (unipileAccount.status !== "connected") {
      const msg = unipileAccount.status === "disconnected"
        ? "Email account disconnected. Reconnect via nurge connect gmail"
        : "Email account auth expired. Re-authenticate via nurge connect gmail";
      return jsonResponse({ ok: false, error: msg }, 400);
    }

    // --- Resolve mailbox ---
    const mailboxId = sequence?.mailboxId || null;
    const mailbox = mailboxId
      ? await ctx.runQuery(internal.sendApi.findMailboxById, { externalId: mailboxId })
      : await ctx.runQuery(internal.sendApi.findActiveMailbox, { userId });

    if (!mailbox) {
      return jsonResponse({ ok: false, error: "No active mailbox found" }, 400);
    }
    if (mailbox.status === "auth_expired") {
      return jsonResponse({ ok: false, error: "Mailbox auth expired. Re-authenticate via nurge connect gmail" }, 400);
    }

    // --- Suppression check ---
    const suppression = await ctx.runQuery(internal.sendApi.checkSuppression, { userId, email: to });
    if (suppression.suppressed) {
      return jsonResponse({ ok: false, error: `Contact suppressed: ${suppression.reason}` }, 400);
    }

    // --- Send window + daily cap ---
    const effectiveSendType = sendType || "first_touch";
    if (!withinSendWindow(mailbox.sendWindowStartHour, mailbox.sendWindowEndHour, mailbox.sendWindowTimezone)) {
      if (sync) {
        return jsonResponse({ ok: false, error: "Outside send window" }, 400);
      }
      // Async: task will be picked up when window opens
    }

    const today = todayInTimezone(mailbox.sendWindowTimezone);
    const sendCount = await ctx.runQuery(internal.sendApi.countSends, {
      mailboxId: mailbox.externalId,
      sendType: effectiveSendType,
      day: today,
    });
    const capMap: Record<string, number> = {
      first_touch: mailbox.firstTouchDailyCap,
      follow_up: mailbox.followUpDailyCap,
      reply: mailbox.replyDailyCap,
    };
    const cap = capMap[effectiveSendType] || 0;
    if (cap > 0 && sendCount >= cap) {
      if (sync) {
        return jsonResponse({ ok: false, error: `Daily ${effectiveSendType} cap reached (${cap})` }, 400);
      }
    }

    // --- Generate IDs ---
    const now = new Date().toISOString();
    const taskExternalId = generateId("task");
    const enrollmentExternalId = sequence ? generateId("enr") : "";

    // --- Create enrollment + future tasks if sequence ---
    if (sequence) {
      // Check for existing active enrollment
      const existingEnrollment = await ctx.runQuery(internal.sendApi.findActiveEnrollment, {
        userId,
        mailboxId: mailbox.externalId,
        contactEmail: to,
      });
      if (existingEnrollment) {
        return jsonResponse({
          ok: false,
          error: `${to} already has an active sequence enrollment (${existingEnrollment.externalId})`,
        }, 400);
      }

      try {
        await ctx.runMutation(internal.sendApi.createSendEnrollment, {
          userId,
          enrollment: {
            externalId: enrollmentExternalId,
            sequenceName: sequence.sequenceName,
            campaignName: sequence.campaignName || "",
            mailboxId: mailbox.externalId,
            contactEmail: to,
            contactName: sequence.contactName || "",
            subject,
            currentStep: 1,
            totalSteps: 1 + (sequence.steps?.length || 0),
            initialBody: body,
            unipileAccountId: unipileAccount.unipileAccountId,
          },
          firstTask: {
            externalId: taskExternalId,
            stepNumber: 1,
            stepName: "first_touch",
            sendType: "first_touch",
            dueAt: now,
            subject,
            body,
            contactEmail: to,
            mailboxId: mailbox.externalId,
          },
          futureSteps: (sequence.steps || []).map((step: SequenceStep, i: number) => {
            const stepTaskId = `${generateId("task")}-s${step.stepNumber || i + 2}`;
            const draftId = `${generateId("draft")}-s${step.stepNumber || i + 2}`;
            // Clamp negative delayDays to 0
            const delayDays = Math.max(0, step.delayDays ?? 3);
            const dueDate = new Date(Date.now() + delayDays * 86400000).toISOString();
            return {
              task: {
                externalId: stepTaskId,
                stepNumber: step.stepNumber || i + 2,
                stepName: step.stepName || `follow_up_${i + 1}`,
                sendType: step.sendType || "follow_up",
                dueAt: dueDate,
                subject: step.subject || subject,
                body: step.body || "",
                contactEmail: to,
                mailboxId: mailbox.externalId,
              },
              draft: {
                externalId: draftId,
                taskId: stepTaskId,
                stepNumber: step.stepNumber || i + 2,
                subject: step.subject || subject,
                body: step.body || "",
                channel: "email",
              },
            };
          }),
        });
      } catch (seqError: unknown) {
        const seqMessage = seqError instanceof Error ? seqError.message : String(seqError);
        console.error("Sequence creation failed:", seqMessage);
        // Clean up partial enrollment if creation failed partway through.
        // Note: Convex mutations are atomic, so if createSendEnrollment threw,
        // nothing was committed. This catch is for errors in the action layer.
        return jsonResponse({ ok: false, error: "Failed to create sequence enrollment" }, 500);
      }
    } else {
      // One-off send: create standalone task
      await ctx.runMutation(internal.sendApi.createStandaloneTask, {
        userId,
        task: {
          externalId: taskExternalId,
          enrollmentId: "",
          mailboxId: mailbox.externalId,
          contactEmail: to,
          subject,
          body,
          stepNumber: 1,
          sendType: effectiveSendType,
          dueAt: now,
        },
      });
    }

    // --- Sync: send now ---
    if (sync) {
      const sendResult = await callUnipileSend({
        accountId: unipileAccount.unipileAccountId,
        to,
        subject,
        body,
      });

      if (!sendResult.ok) {
        await ctx.runMutation(internal.sendApi.markTaskFailed, {
          userId,
          taskId: taskExternalId,
          error: sendResult.error,
          authError: sendResult.authError,
          mailboxId: mailbox.externalId,
        });
        return jsonResponse({ ok: false, error: sendResult.error }, 502);
      }

      await ctx.runMutation(internal.sendApi.markTaskSent, {
        userId,
        taskId: taskExternalId,
        enrollmentId: enrollmentExternalId,
        mailboxId: mailbox.externalId,
        sendType: effectiveSendType,
        unipileMessageId: sendResult.messageId,
        providerId: sendResult.providerId,
      });

      return jsonResponse({
        ok: true,
        messageId: sendResult.messageId,
        providerId: sendResult.providerId,
        taskId: taskExternalId,
        enrollmentId: enrollmentExternalId || undefined,
      });
    }

    // --- Async: return queued ---
    return jsonResponse({
      ok: true,
      queued: true,
      taskId: taskExternalId,
      enrollmentId: enrollmentExternalId || undefined,
    });
  } catch (error: unknown) {
    const message = error instanceof Error ? error.message : String(error);
    const stack = error instanceof Error ? error.stack : undefined;
    console.error("sendEmail error:", message, stack);
    // Don't leak internal details to the client
    return jsonResponse({ ok: false, error: "Internal error" }, 500);
  }
});

// Handle sending an existing task (--task-id flow)
async function handleExistingTask(ctx: ActionCtx, userId: string, taskId: string, payload: SendPayload) {
  const task = await ctx.runQuery(internal.sendApi.findTask, { externalId: taskId });
  if (!task) {
    return jsonResponse({ ok: false, error: `Task ${taskId} not found` }, 404);
  }
  if (task.userId !== userId) {
    return jsonResponse({ ok: false, error: "Task does not belong to this user" }, 403);
  }
  if (task.status !== "open") {
    return jsonResponse({ ok: false, error: `Task is ${task.status}, not open` }, 400);
  }
  if (task.sendStatus === "sent") {
    return jsonResponse({ ok: false, error: "Task already sent" }, 400);
  }

  // Resolve Unipile account
  const unipileAccount = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
    userId,
    provider: "GOOGLE",
  });
  if (!unipileAccount) {
    return jsonResponse({ ok: false, error: "No connected email account" }, 400);
  }
  if (unipileAccount.status !== "connected") {
    const msg = unipileAccount.status === "disconnected"
      ? "Email account disconnected. Reconnect via nurge connect gmail"
      : "Email account auth expired. Re-authenticate via nurge connect gmail";
    return jsonResponse({ ok: false, error: msg }, 400);
  }

  // Use payload overrides or task defaults
  const to = payload.to || task.contactEmail;
  const subject = payload.subject || task.subject || "";
  const body = payload.body || task.body || "";

  // Look up draft for latest content
  const draft = await ctx.runQuery(internal.sendApi.findDraft, { taskId });
  const finalSubject = subject || draft?.subject || "";
  const finalBody = body || draft?.body || "";

  if (!finalSubject || !finalBody) {
    return jsonResponse({ ok: false, error: "No subject or body available for this task" }, 400);
  }

  // Get enrollment for threading
  const enrollment = task.enrollmentId
    ? await ctx.runQuery(internal.sendApi.findEnrollment, { externalId: task.enrollmentId })
    : null;

  const replyTo = enrollment?.unipileThreadProviderId || undefined;

  const sendResult = await callUnipileSend({
    accountId: unipileAccount.unipileAccountId,
    to,
    subject: finalSubject,
    body: finalBody,
    replyTo,
  });

  if (!sendResult.ok) {
    await ctx.runMutation(internal.sendApi.markTaskFailed, {
      userId,
      taskId,
      error: sendResult.error,
      authError: sendResult.authError,
      mailboxId: task.mailboxId,
    });
    return jsonResponse({ ok: false, error: sendResult.error }, 502);
  }

  await ctx.runMutation(internal.sendApi.markTaskSent, {
    userId,
    taskId,
    enrollmentId: task.enrollmentId,
    mailboxId: task.mailboxId,
    sendType: task.sendType,
    unipileMessageId: sendResult.messageId,
    providerId: sendResult.providerId,
  });

  return jsonResponse({
    ok: true,
    messageId: sendResult.messageId,
    providerId: sendResult.providerId,
    taskId,
    enrollmentId: task.enrollmentId || undefined,
  });
}

function jsonResponse(data: Record<string, unknown>, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json" },
  });
}

// --- Internal queries/mutations used by the httpAction ---

export const findUserByToken = internalQuery({
  args: { token: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("users")
      .withIndex("by_token", (q) => q.eq("token", args.token))
      .first();
  },
});

export const findUnipileAccount = internalQuery({
  args: { userId: v.string(), provider: v.string() },
  handler: async (ctx, args) => {
    const accounts = await ctx.db
      .query("unipileAccounts")
      .withIndex("by_provider", (q) =>
        q.eq("userId", args.userId).eq("provider", args.provider)
      )
      .collect();
    // Prefer connected account; fall back to any (caller checks status)
    return accounts.find((a) => a.status === "connected")
      || accounts[0]
      || null;
  },
});

export const findMailboxById = internalQuery({
  args: { externalId: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("mailboxes")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.externalId))
      .first();
  },
});

export const findActiveMailbox = internalQuery({
  args: { userId: v.string() },
  handler: async (ctx, args) => {
    const mailboxes = await ctx.db
      .query("mailboxes")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .collect();
    return mailboxes.find((m) => m.status === "active") || null;
  },
});

export const checkSuppression = internalQuery({
  args: { userId: v.string(), email: v.string() },
  handler: async (ctx, args) => {
    return await isSuppressed(ctx, args.userId, args.email);
  },
});

export const countSends = internalQuery({
  args: { mailboxId: v.string(), sendType: v.string(), day: v.string() },
  handler: async (ctx, args) => {
    return await countSendsForDay(ctx, args.mailboxId, args.sendType, args.day);
  },
});

export const findActiveEnrollment = internalQuery({
  args: { userId: v.string(), mailboxId: v.string(), contactEmail: v.string() },
  handler: async (ctx, args) => {
    const enrollments = await ctx.db
      .query("sequenceEnrollments")
      .withIndex("by_contact", (q) =>
        q.eq("userId", args.userId).eq("contactEmail", args.contactEmail)
      )
      .collect();
    return enrollments.find((e) => e.status === "active") || null;
  },
});

export const findTask = internalQuery({
  args: { externalId: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("followUpTasks")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.externalId))
      .first();
  },
});

export const findDraft = internalQuery({
  args: { taskId: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("sequenceDrafts")
      .withIndex("by_task", (q) => q.eq("taskId", args.taskId))
      .first();
  },
});

export const findEnrollment = internalQuery({
  args: { externalId: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("sequenceEnrollments")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.externalId))
      .first();
  },
});

export const createStandaloneTask = internalMutation({
  args: {
    userId: v.string(),
    task: v.object({
      externalId: v.string(),
      enrollmentId: v.string(),
      mailboxId: v.string(),
      contactEmail: v.string(),
      subject: v.string(),
      body: v.string(),
      stepNumber: v.float64(),
      sendType: v.string(),
      dueAt: v.string(),
    }),
  },
  handler: async (ctx, args) => {
    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    const version = (syncState?.lastSyncVersion ?? 0) + 1;

    await ctx.db.insert("followUpTasks", {
      ...args.task,
      threadId: "",
      stepName: "manual",
      status: "open",
      sendStatus: "pending",
      attemptCount: 0,
      syncVersion: version,
      userId: args.userId,
    });

    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
    } else {
      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
    }
  },
});

export const createSendEnrollment = internalMutation({
  args: {
    userId: v.string(),
    enrollment: v.object({
      externalId: v.string(),
      sequenceName: v.string(),
      campaignName: v.string(),
      mailboxId: v.string(),
      contactEmail: v.string(),
      contactName: v.string(),
      subject: v.string(),
      currentStep: v.float64(),
      totalSteps: v.float64(),
      initialBody: v.string(),
      unipileAccountId: v.string(),
    }),
    firstTask: v.object({
      externalId: v.string(),
      stepNumber: v.float64(),
      stepName: v.string(),
      sendType: v.string(),
      dueAt: v.string(),
      subject: v.string(),
      body: v.string(),
      contactEmail: v.string(),
      mailboxId: v.string(),
    }),
    futureSteps: v.array(
      v.object({
        task: v.object({
          externalId: v.string(),
          stepNumber: v.float64(),
          stepName: v.string(),
          sendType: v.string(),
          dueAt: v.string(),
          subject: v.string(),
          body: v.string(),
          contactEmail: v.string(),
          mailboxId: v.string(),
        }),
        draft: v.object({
          externalId: v.string(),
          taskId: v.string(),
          stepNumber: v.float64(),
          subject: v.string(),
          body: v.string(),
          channel: v.string(),
        }),
      })
    ),
  },
  handler: async (ctx, args) => {
    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    let version = (syncState?.lastSyncVersion ?? 0) + 1;

    // Create enrollment
    await ctx.db.insert("sequenceEnrollments", {
      externalId: args.enrollment.externalId,
      sequenceName: args.enrollment.sequenceName,
      campaignName: args.enrollment.campaignName,
      mailboxId: args.enrollment.mailboxId,
      contactEmail: args.enrollment.contactEmail,
      contactName: args.enrollment.contactName,
      subject: args.enrollment.subject,
      currentStep: args.enrollment.currentStep,
      totalSteps: args.enrollment.totalSteps,
      initialBody: args.enrollment.initialBody,
      unipileAccountId: args.enrollment.unipileAccountId,
      status: "active",
      statusReason: "",
      replyState: "",
      lastSentAt: new Date().toISOString(),
      nextDueAt: args.firstTask.dueAt,
      syncVersion: version,
      userId: args.userId,
    });

    // Create first task
    await ctx.db.insert("followUpTasks", {
      externalId: args.firstTask.externalId,
      enrollmentId: args.enrollment.externalId,
      mailboxId: args.firstTask.mailboxId,
      contactEmail: args.firstTask.contactEmail,
      subject: args.firstTask.subject,
      body: args.firstTask.body,
      threadId: "",
      stepNumber: args.firstTask.stepNumber,
      stepName: args.firstTask.stepName,
      sendType: args.firstTask.sendType,
      status: "open",
      sendStatus: "pending",
      dueAt: args.firstTask.dueAt,
      attemptCount: 0,
      syncVersion: version,
      userId: args.userId,
    });

    // Create future tasks + drafts
    for (const step of args.futureSteps) {
      await ctx.db.insert("followUpTasks", {
        externalId: step.task.externalId,
        enrollmentId: args.enrollment.externalId,
        mailboxId: step.task.mailboxId,
        contactEmail: step.task.contactEmail,
        subject: step.task.subject,
        body: step.task.body,
        threadId: "",
        stepNumber: step.task.stepNumber,
        stepName: step.task.stepName,
        sendType: step.task.sendType,
        status: "open",
        sendStatus: "pending",
        dueAt: step.task.dueAt,
        attemptCount: 0,
        syncVersion: version,
        userId: args.userId,
      });

      await ctx.db.insert("sequenceDrafts", {
        externalId: step.draft.externalId,
        enrollmentId: args.enrollment.externalId,
        taskId: step.draft.taskId,
        stepNumber: step.draft.stepNumber,
        subject: step.draft.subject,
        body: step.draft.body,
        channel: step.draft.channel,
        status: "pending",
        syncVersion: version,
        userId: args.userId,
      });
    }

    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
    } else {
      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
    }
  },
});

export const markTaskSent = internalMutation({
  args: {
    userId: v.string(),
    taskId: v.string(),
    enrollmentId: v.string(),
    mailboxId: v.string(),
    sendType: v.string(),
    unipileMessageId: v.string(),
    providerId: v.string(),
  },
  handler: async (ctx, args) => {
    const task = await ctx.db
      .query("followUpTasks")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
      .first();
    if (!task) return;

    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    let version = (syncState?.lastSyncVersion ?? 0) + 1;

    // Update task
    await ctx.db.patch(task._id, {
      status: "completed",
      sendStatus: "sent",
      completedAt: new Date().toISOString(),
      unipileMessageId: args.unipileMessageId,
      providerId: args.providerId,
      syncVersion: version,
    });

    // Create send event
    const sendEventId = generateId("mse");
    await ctx.db.insert("mailboxSendEvents", {
      externalId: sendEventId,
      mailboxId: args.mailboxId,
      sendType: args.sendType,
      sentAt: new Date().toISOString(),
      taskId: args.taskId,
      enrollmentId: args.enrollmentId,
      unipileMessageId: args.unipileMessageId,
      providerId: args.providerId,
      syncVersion: version,
      userId: args.userId,
    });

    // Advance enrollment if applicable
    if (args.enrollmentId) {
      const enrollment = await ctx.db
        .query("sequenceEnrollments")
        .withIndex("by_external_id", (q) => q.eq("externalId", args.enrollmentId))
        .first();

      if (enrollment) {
        version++;
        const newStep = task.stepNumber;
        const isComplete = newStep >= enrollment.totalSteps;

        await ctx.db.patch(enrollment._id, {
          currentStep: newStep,
          lastSentAt: new Date().toISOString(),
          lastMessageId: args.unipileMessageId,
          status: isComplete ? "completed" : enrollment.status,
          nextDueAt: isComplete ? "" : enrollment.nextDueAt,
          unipileThreadProviderId: args.providerId || enrollment.unipileThreadProviderId,
          syncVersion: version,
        });

        // Mark draft as sent
        const draft = await ctx.db
          .query("sequenceDrafts")
          .withIndex("by_task", (q) => q.eq("taskId", args.taskId))
          .first();
        if (draft) {
          await ctx.db.patch(draft._id, {
            status: "sent",
            syncVersion: version,
          });
        }
      }
    }

    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
    } else {
      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
    }
  },
});

export const markTaskFailed = internalMutation({
  args: {
    userId: v.string(),
    taskId: v.string(),
    error: v.string(),
    authError: v.boolean(),
    mailboxId: v.string(),
  },
  handler: async (ctx, args) => {
    const task = await ctx.db
      .query("followUpTasks")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
      .first();
    if (!task) return;

    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    let version = (syncState?.lastSyncVersion ?? 0) + 1;

    const newAttemptCount = task.attemptCount + 1;

    await ctx.db.patch(task._id, {
      sendStatus: args.authError ? "failed" : "pending", // auth errors don't retry
      lastAttemptAt: new Date().toISOString(),
      lastError: args.error,
      attemptCount: newAttemptCount,
      syncVersion: version,
    });

    // Mark mailbox auth_expired on auth errors
    if (args.authError && args.mailboxId) {
      const mailbox = await ctx.db
        .query("mailboxes")
        .withIndex("by_external_id", (q) => q.eq("externalId", args.mailboxId))
        .first();
      if (mailbox) {
        version++;
        await ctx.db.patch(mailbox._id, {
          status: "auth_expired",
          syncVersion: version,
        });
      }
    }

    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
    } else {
      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
    }
  },
});

