import { v } from "convex/values";
import { internalAction, internalQuery, internalMutation } from "./_generated/server";
import { internal } from "./_generated/api";
import {
  isSuppressed,
  countSendsForDay,
  todayInTimezone,
  withinSendWindow,
} from "./helpers";

const BATCH_SIZE = 10;

// Email dispatch via Unipile (secondary path).
// The primary EMAIL send path is now local: `nurge dispatcher run --execute`
// uses Gmail API directly. This Convex action remains active for:
// - LinkedIn messaging (Unipile is the only LinkedIn transport)
// - Users who explicitly choose Unipile for email (multi-provider, open tracking)
export const checkDueTasks = internalAction({
  handler: async (ctx) => {
    const now = new Date().toISOString();

    const dueTasks = await ctx.runQuery(internal.dispatcher.findDueTasks, {
      now,
      limit: BATCH_SIZE,
    });

    if (dueTasks.length === 0) return;

    for (const task of dueTasks) {
      try {
        const enrollment = await ctx.runQuery(
          internal.dispatcher.getEnrollment,
          { enrollmentId: task.enrollmentId }
        );
        if (!enrollment || enrollment.status !== "active") continue;

        const suppression = await ctx.runQuery(
          internal.dispatcher.checkSuppression,
          { userId: task.userId, email: task.contactEmail }
        );
        if (suppression.suppressed) {
          await ctx.runMutation(internal.dispatcher.cancelTask, {
            taskId: task.externalId,
            userId: task.userId,
            reason: `Contact suppressed: ${suppression.reason}`,
          });
          continue;
        }

        const mailbox = await ctx.runQuery(
          internal.dispatcher.getMailbox,
          { mailboxId: task.mailboxId }
        );
        if (!mailbox || mailbox.status !== "active") continue;
        if (
          !withinSendWindow(
            mailbox.sendWindowStartHour,
            mailbox.sendWindowEndHour,
            mailbox.sendWindowTimezone
          )
        ) {
          continue;
        }

        const today = todayInTimezone(mailbox.sendWindowTimezone);
        const sendCount = await ctx.runQuery(
          internal.dispatcher.countSends,
          { mailboxId: task.mailboxId, sendType: task.sendType, day: today }
        );

        const capMap: Record<string, number> = {
          first_touch: mailbox.firstTouchDailyCap,
          follow_up: mailbox.followUpDailyCap,
          reply: mailbox.replyDailyCap,
        };
        const cap = capMap[task.sendType] || 0;
        if (cap > 0 && sendCount >= cap) continue;

        const draft = await ctx.runQuery(
          internal.dispatcher.getDraft,
          { taskId: task.externalId }
        );
        if (draft && draft.status === "stale") continue;

        const claimed = await ctx.runMutation(internal.dispatcher.claimTask, {
          taskId: task.externalId,
          userId: task.userId,
        });

        // Skip if task was already claimed by another run
        if (!claimed) continue;

        const unipileAccount = await ctx.runQuery(
          internal.dispatcher.getUnipileAccount,
          { userId: task.userId, provider: "GOOGLE" }
        );
        if (!unipileAccount) continue;

        const subject = draft?.subject || task.subject || "";
        const body = draft?.body || task.body || "";

        await ctx.runAction(internal.send.sendViaUnipile, {
          userId: task.userId,
          taskId: task.externalId,
          accountId: unipileAccount.unipileAccountId,
          to: task.contactEmail,
          subject,
          body,
          replyTo: enrollment.unipileThreadProviderId || undefined,
        });
      } catch (error) {
        console.error(`Error processing task ${task.externalId}:`, error);
        // Mark task as failed so it doesn't stay stuck in pending_remote_send forever
        try {
          await ctx.runMutation(internal.dispatcher.failTask, {
            taskId: task.externalId,
            userId: task.userId,
            error: error instanceof Error ? error.message : "Unknown dispatch error",
          });
        } catch (failError) {
          console.error(`Failed to mark task ${task.externalId} as failed:`, failError);
        }
      }
    }
  },
});

// --- Internal queries/mutations used by checkDueTasks ---

export const findDueTasks = internalQuery({
  args: { now: v.string(), limit: v.float64() },
  handler: async (ctx, args) => {
    const tasks = await ctx.db
      .query("followUpTasks")
      .filter((q) =>
        q.and(
          q.eq(q.field("sendStatus"), "pending"),
          q.eq(q.field("status"), "open"),
          q.lte(q.field("dueAt"), args.now)
        )
      )
      .take(args.limit);

    return tasks.map((t) => ({
      externalId: t.externalId,
      enrollmentId: t.enrollmentId,
      mailboxId: t.mailboxId,
      contactEmail: t.contactEmail,
      sendType: t.sendType,
      subject: t.subject,
      body: t.body,
      userId: t.userId,
    }));
  },
});

