      .first();
  },
});

export const getUnipileAccount = internalQuery({
  args: { userId: v.string(), provider: v.string() },
  handler: async (ctx, args) => {
    const accounts = await ctx.db
      .query("unipileAccounts")
      .withIndex("by_provider", (q) =>
        q.eq("userId", args.userId).eq("provider", args.provider)
      )
      .collect();
    // Prefer connected accounts; skip disconnected/expired
    return accounts.find((a) => a.status === "connected") || null;
  },
});

export const claimTask = internalMutation({
  args: { taskId: v.string(), userId: v.string() },
  handler: async (ctx, args) => {
    const task = await ctx.db
      .query("followUpTasks")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
      .first();
    if (!task) return null;

    // Atomic claim: only claim if still pending (prevents double-processing)
    if (task.sendStatus !== "pending") {
      console.log(`Task ${args.taskId} already claimed (status: ${task.sendStatus}), skipping`);
      return null;
    }

    await ctx.db.patch(task._id, {
      sendStatus: "pending_remote_send",
      lastAttemptAt: new Date().toISOString(),
    });
    return { claimed: true };
  },
});

export const failTask = internalMutation({
  args: { taskId: v.string(), userId: v.string(), error: v.string() },
  handler: async (ctx, args) => {
    const task = await ctx.db
      .query("followUpTasks")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
      .first();
    if (!task) return;

    const newAttemptCount = task.attemptCount + 1;
    const maxRetries = 5;

    // If task has been retrying too long (> 7 days), mark permanently failed
    const dueAt = new Date(task.dueAt).getTime();
    const maxRetryAgeMs = 7 * 24 * 60 * 60 * 1000;
    const isTooOld = Date.now() - dueAt > maxRetryAgeMs;
    const isPermanentlyFailed = newAttemptCount >= maxRetries || isTooOld;

    await ctx.db.patch(task._id, {
      sendStatus: isPermanentlyFailed ? "failed" : "pending",
      lastAttemptAt: new Date().toISOString(),
      lastError: args.error,
      attemptCount: newAttemptCount,
      status: isPermanentlyFailed ? "canceled" : task.status,
      canceledReason: isPermanentlyFailed
        ? isTooOld
          ? "stale: past 7-day retry window"
          : `max retries (${maxRetries}) exceeded`
        : task.canceledReason,
    });
  },
});

export const cancelTask = internalMutation({
  args: { taskId: v.string(), userId: v.string(), reason: v.string() },
  handler: async (ctx, args) => {
    const task = await ctx.db
      .query("followUpTasks")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
      .first();
    if (!task) return;

    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    const version = (syncState?.lastSyncVersion ?? 0) + 1;

    await ctx.db.patch(task._id, {
      status: "canceled",
      sendStatus: "canceled",
      canceledReason: args.reason,
      syncVersion: version,
    });

    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
    } else {
      await ctx.db.insert("syncState", {
        userId: args.userId,
        lastSyncVersion: version,
      });
    }
  },
});

