  1→// convex/gmailApi.ts
  2→//
  3→// Gmail API helpers for server-side reply fetching.
  4→// Uses stored refresh token to get access token, then calls history.list
  5→// to find new messages since the last known historyId.
  6→
  7→import { v } from "convex/values";
  8→import {
  9→  type ActionCtx,
 10→  internalAction,
 11→  internalMutation,
 12→  internalQuery,
 13→  httpAction,
 14→} from "./_generated/server";
 15→import { internal } from "./_generated/api";
 16→import { decryptToken } from "./crypto";
 17→
 18→const GMAIL_TOKEN_URL = "https://oauth2.googleapis.com/token";
 19→const GMAIL_API_BASE = "https://gmail.googleapis.com/gmail/v1/users/me";
 20→
 21→// ── Gmail API helpers ───────────────────────────────────────────────
 22→
 23→async function getAccessToken(
 24→  refreshToken: string,
 25→  retryCount = 0
 26→): Promise<string> {
 27→  const clientId = process.env.GMAIL_CLIENT_ID;
 28→  const clientSecret = process.env.GMAIL_CLIENT_SECRET;
 29→  if (!clientId || !clientSecret) {
 30→    throw new Error(
 31→      "GMAIL_CLIENT_ID and GMAIL_CLIENT_SECRET env vars required"
 32→    );
 33→  }
 34→
 35→  // 10s timeout for token refresh
 36→  const controller = new AbortController();
 37→  const timeoutId = setTimeout(() => controller.abort(), 10000);
 38→
 39→  let resp: Response;
 40→  try {
 41→    resp = await fetch(GMAIL_TOKEN_URL, {
 42→      method: "POST",
 43→      headers: { "Content-Type": "application/x-www-form-urlencoded" },
 44→      body: new URLSearchParams({
 45→        client_id: clientId,
 46→        client_secret: clientSecret,
 47→        refresh_token: refreshToken,
 48→        grant_type: "refresh_token",
 49→      }),
 50→      signal: controller.signal,
 51→    });
 52→  } catch (fetchError: unknown) {
 53→    clearTimeout(timeoutId);
 54→    if (fetchError instanceof Error && fetchError.name === "AbortError") {
 55→      // Retry with exponential backoff (max 3 retries)
 56→      if (retryCount < 3) {
 57→        const delay = Math.pow(2, retryCount) * 1000; // 1s, 2s, 4s
 58→        await new Promise((r) => setTimeout(r, delay));
 59→        return getAccessToken(refreshToken, retryCount + 1);
 60→      }
 61→      throw new Error("Token refresh timed out after 3 retries");
 62→    }
 63→    throw fetchError;
 64→  }
 65→  clearTimeout(timeoutId);
 66→
 67→  if (!resp.ok) {
 68→    const err = await resp.text();
 69→    // Retry on 5xx errors with exponential backoff
 70→    if (resp.status >= 500 && retryCount < 3) {
 71→      const delay = Math.pow(2, retryCount) * 1000;
 72→      await new Promise((r) => setTimeout(r, delay));
 73→      return getAccessToken(refreshToken, retryCount + 1);
 74→    }
 75→    throw new Error(`Token refresh failed (${resp.status}): ${err}`);
 76→  }
 77→
 78→  const data = await resp.json();
 79→
 80→  // Validate response contains access_token
 81→  if (!data.access_token) {
 82→    throw new Error("Token refresh response missing access_token field");
 83→  }
 84→
 85→  return data.access_token;
 86→}
 87→
 88→async function fetchHistoryMessages(
 89→  accessToken: string,
 90→  historyId: string
 91→): Promise<{ messages: Array<{ id: string; threadId: string }>; historyGap: boolean }> {
 92→  const messages: Array<{ id: string; threadId: string }> = [];
 93→  let pageToken: string | undefined;
 94→
 95→  do {
 96→    let url = `${GMAIL_API_BASE}/history?startHistoryId=${historyId}&historyTypes=messageAdded&labelId=INBOX`;
 97→    if (pageToken) {
 98→      url += `&pageToken=${pageToken}`;
 99→    }
100→
101→    // 15s timeout for history.list
102→    const histController = new AbortController();
103→    const histTimeout = setTimeout(() => histController.abort(), 15000);
104→
105→    let resp: Response;
106→    try {
107→      resp = await fetch(url, {
108→        headers: { Authorization: `Bearer ${accessToken}` },
109→        signal: histController.signal,
110→      });
111→    } catch (fetchErr: unknown) {
112→      clearTimeout(histTimeout);
113→      if (fetchErr instanceof Error && fetchErr.name === "AbortError") {
114→        throw new Error("history.list request timed out (15s)");
115→      }
116→      throw fetchErr;
117→    }
118→    clearTimeout(histTimeout);
119→
120→    if (!resp.ok) {
121→      if (resp.status === 404) {
122→        // historyId too old -- Gmail purged history. Flag so caller can handle.
123→        console.error(`Gmail history.list 404: historyId ${historyId} is too old. Replies in the gap may be lost.`);
124→        return { messages: [], historyGap: true };
125→      }
126→      throw new Error(`history.list failed (${resp.status})`);
127→    }
128→
129→    const data = await resp.json();
130→
131→    for (const record of data.history || []) {
132→      for (const msg of record.messagesAdded || []) {
133→        messages.push({
134→          id: msg.message.id,
135→          threadId: msg.message.threadId,
136→        });
137→      }
138→    }
139→
140→    pageToken = data.nextPageToken;
141→  } while (pageToken);
142→
143→  return { messages, historyGap: false };
144→}
145→
146→async function fetchMessage(
147→  accessToken: string,
148→  messageId: string
149→): Promise<{
150→  id: string;
151→  threadId: string;
152→  from: string;
153→  to: string;
154→  subject: string;
155→  snippet: string;
156→  date: string;
157→  inReplyTo: string;
158→}> {
159→  const url = `${GMAIL_API_BASE}/messages/${messageId}?format=metadata&metadataHeaders=From&metadataHeaders=To&metadataHeaders=Subject&metadataHeaders=Date&metadataHeaders=In-Reply-To`;
160→
161→  // 10s timeout for messages.get
162→  const msgController = new AbortController();
163→  const msgTimeout = setTimeout(() => msgController.abort(), 10000);
164→
165→  let resp: Response;
166→  try {
167→    resp = await fetch(url, {
168→      headers: { Authorization: `Bearer ${accessToken}` },
169→      signal: msgController.signal,
170→    });
171→  } catch (fetchErr: unknown) {
172→    clearTimeout(msgTimeout);
173→    if (fetchErr instanceof Error && fetchErr.name === "AbortError") {
174→      throw new Error(`messages.get timed out for ${messageId} (10s)`);
175→    }
176→    throw fetchErr;
177→  }
178→  clearTimeout(msgTimeout);
179→
180→  if (!resp.ok) {
181→    throw new Error(`messages.get failed (${resp.status})`);
182→  }
183→
184→  const data = await resp.json();
185→  const headers: Record<string, string> = {};
186→  for (const h of data.payload?.headers || []) {
187→    headers[h.name.toLowerCase()] = h.value;
188→  }
189→
190→  return {
191→    id: data.id,
192→    threadId: data.threadId,
193→    from: headers["from"] || "",
194→    to: headers["to"] || "",
195→    subject: headers["subject"] || "",
196→    snippet: data.snippet || "",
197→    date: headers["date"] || "",
198→    inReplyTo: headers["in-reply-to"] || "",
199→  };
200→}
201→
202→function extractEmail(fromHeader: string): string {
203→  const match = fromHeader.match(/<([^>]+)>/);
204→  return match ? match[1].toLowerCase() : fromHeader.toLowerCase().trim();
205→}
206→
207→// ── Main action: fetch new replies ──────────────────────────────────
208→
209→type FetchGmailRepliesArgs = {
210→  email: string;
211→  historyId: string;
212→};
213→
214→type FetchGmailRepliesResult = {
215→  repliesFound: number;
216→  error?: string;
217→};
218→
219→const fetchGmailRepliesHandler = async (
220→  ctx: ActionCtx,
221→  args: FetchGmailRepliesArgs
222→): Promise<FetchGmailRepliesResult> => {
223→  // 1. Look up stored credentials
224→  const creds = await ctx.runQuery(internal.gmailApi.getCredentials, {
225→    email: args.email,
226→  });
227→  if (!creds || creds.status !== "active") {
228→    console.log(`No active Gmail credentials for ${args.email}`);
229→    return {
230→      repliesFound: 0,
231→      error: creds ? "credentials_" + creds.status : "no_credentials",
232→    };
233→  }
234→
235→  // 2. Decrypt refresh token
236→  let refreshToken: string;
237→  try {
238→    refreshToken = await decryptToken(
239→      creds.encryptedRefreshToken,
240→      creds.tokenIv
241→    );
242→  } catch (e: unknown) {
243→    const message = e instanceof Error ? e.message : String(e);
244→    console.error("Failed to decrypt Gmail token:", message);
245→    await ctx.runMutation(internal.gmailApi.markCredentialsExpired, {
246→      email: args.email,
247→    });
248→    return { repliesFound: 0, error: "decrypt_failed" };
249→  }
250→
251→  // 3. Get access token
252→  let accessToken: string;
253→  try {
254→    accessToken = await getAccessToken(refreshToken);
255→  } catch (e: unknown) {
256→    const message = e instanceof Error ? e.message : String(e);
257→    console.error("Gmail token refresh failed:", message);
258→    await ctx.runMutation(internal.gmailApi.markCredentialsExpired, {
259→      email: args.email,
260→    });
261→    return { repliesFound: 0, error: "token_refresh_failed" };
262→  }
263→
264→  // Update lastUsedAt
265→  await ctx.runMutation(internal.gmailApi.touchCredentials, {
266→    email: args.email,
267→  });
268→
269→  // 4. Fetch history since last historyId
270→  const historyResult = await fetchHistoryMessages(accessToken, args.historyId);
271→  if (historyResult.historyGap) {
272→    console.error(`History gap detected for ${args.email}. Some replies may have been missed.`);
273→  }
274→  const newMessages = historyResult.messages;
275→  if (newMessages.length === 0) {
276→    return { repliesFound: 0 };
277→  }
278→
279→  // 5. For each new message, check if it's a reply to our outbound
280→  let repliesFound = 0;
281→  for (const msg of newMessages) {
282→    try {
283→      const message = await fetchMessage(accessToken, msg.id);
284→
285→      // Skip messages FROM the user's own email (outbound, not inbound)
286→      if (message.from.toLowerCase().includes(args.email.toLowerCase())) {
287→        continue;
288→      }
289→
290→      // Only process if it's a reply (has In-Reply-To or is in a tracked thread)
291→      if (!message.inReplyTo && !message.threadId) {
292→        continue;
293→      }
294→
295→      // Check if this thread belongs to one of our enrollments
296→      const enrollment = await ctx.runQuery(
297→        internal.gmailApi.findEnrollmentByThread,
298→        {
299→          threadId: message.threadId,
300→          email: args.email,
301→        }
302→      );
303→
304→      if (!enrollment) {
305→        continue; // Not a reply to our outbound
306→      }
307→
308→      // 6. Create reply draft via replyDrafts module
309→      await ctx.runMutation(internal.replyDrafts.createFromReply, {
310→        userId: enrollment.userId,
311→        enrollmentId: enrollment.externalId,
312→        mailboxId: enrollment.mailboxId,
313→        threadId: message.threadId,
314→        messageId: message.id,
315→        contactEmail: extractEmail(message.from),
316→        subject: message.subject,
317→        snippet: message.snippet,
318→        occurredAt: new Date().toISOString(),
319→      });
320→
321→      repliesFound++;
322→    } catch (e: unknown) {
323→      const message = e instanceof Error ? e.message : String(e);
324→      console.error(`Error processing message ${msg.id}:`, message);
325→    }
326→  }
327→
328→  return { repliesFound };
329→};
330→
331→export const fetchGmailReplies = internalAction({
332→  args: {
333→    email: v.string(),
334→    historyId: v.string(),
335→  },
336→  handler: fetchGmailRepliesHandler,
337→});
