339→// ── Gmail send (direct, no Unipile) ─────────────────────────────────
340→
341→function buildRfc2822Message(
342→  from: string,
343→  to: string,
344→  subject: string,
345→  body: string,
346→  inReplyTo?: string
347→): string {
348→  const boundary = `boundary_${Date.now()}_${Math.random().toString(36).slice(2)}`;
349→  const lines: string[] = [
350→    `From: ${from}`,
351→    `To: ${to}`,
352→    `Subject: ${subject}`,
353→    `MIME-Version: 1.0`,
354→    `Content-Type: multipart/alternative; boundary="${boundary}"`,
355→  ];
356→
357→  if (inReplyTo) {
358→    lines.push(`In-Reply-To: ${inReplyTo}`);
359→    lines.push(`References: ${inReplyTo}`);
360→  }
361→
362→  lines.push(""); // Empty line before body
363→  lines.push(`--${boundary}`);
364→  lines.push("Content-Type: text/plain; charset=UTF-8");
365→  lines.push("");
366→  lines.push(body);
367→  lines.push(`--${boundary}`);
368→  lines.push("Content-Type: text/html; charset=UTF-8");
369→  lines.push("");
370→  lines.push(body.replace(/\n/g, "<br>"));
371→  lines.push(`--${boundary}--`);
372→
373→  return lines.join("\r\n");
374→}
375→
376→function base64UrlEncode(str: string): string {
377→  const encoder = new TextEncoder();
378→  const bytes = encoder.encode(str);
379→  let binary = "";
380→  for (const byte of bytes) {
381→    binary += String.fromCharCode(byte);
382→  }
383→  return btoa(binary)
384→    .replace(/\+/g, "-")
385→    .replace(/\//g, "_")
386→    .replace(/=+$/, "");
387→}
388→
389→export async function callGmailSend(args: {
390→  accessToken: string;
391→  from: string;
392→  to: string;
393→  subject: string;
394→  body: string;
395→  threadId?: string;
396→  inReplyTo?: string;
397→}): Promise<
398→  | { ok: true; messageId: string; threadId: string }
399→  | { ok: false; error: string; authError: boolean }
400→> {
401→  const raw = buildRfc2822Message(
402→    args.from,
403→    args.to,
404→    args.subject,
405→    args.body,
406→    args.inReplyTo
407→  );
408→
409→  const payload: Record<string, string> = {
410→    raw: base64UrlEncode(raw),
411→  };
412→
413→  if (args.threadId) {
414→    payload.threadId = args.threadId;
415→  }
416→
417→  const controller = new AbortController();
418→  const timeoutId = setTimeout(() => controller.abort(), 30000);
419→
420→  let resp: Response;
421→  try {
422→    resp = await fetch(`${GMAIL_API_BASE}/messages/send`, {
423→      method: "POST",
424→      headers: {
425→        Authorization: `Bearer ${args.accessToken}`,
426→        "Content-Type": "application/json",
427→      },
428→      body: JSON.stringify(payload),
429→      signal: controller.signal,
430→    });
431→  } catch (fetchError: any) {
432→    clearTimeout(timeoutId);
433→    if (fetchError.name === "AbortError") {
434→      return { ok: false, error: "Gmail send timed out (30s)", authError: false };
435→    }
436→    return { ok: false, error: `Gmail send error: ${fetchError.message}`, authError: false };
437→  }
438→  clearTimeout(timeoutId);
439→
440→  if (!resp.ok) {
441→    const errorText = await resp.text();
442→    const isAuth = resp.status === 401 || resp.status === 403;
443→    return {
444→      ok: false,
445→      error: isAuth
446→        ? `Gmail auth error: ${errorText}`
447→        : `Gmail API error ${resp.status}: ${errorText}`,
448→      authError: isAuth,
449→    };
450→  }
451→
452→  const result = await resp.json();
453→  return {
454→    ok: true,
455→    messageId: result.id || "",
456→    threadId: result.threadId || "",
457→  };
458→}
