460→// Get an access token for a user by looking up their stored Gmail credentials.
461→// Used by the Slack approve-to-send flow and any server-side send operation.
462→export async function getAccessTokenForUser(
463→  ctx: ActionCtx,
464→  userId: string
465→): Promise<{ accessToken: string; email: string } | null> {
466→  const creds = await ctx.runQuery(internal.gmailApi.getCredentialsByUser, {
467→    userId,
468→  });
469→  if (!creds || creds.status !== "active") return null;
470→
471→  let refreshToken: string;
472→  try {
473→    refreshToken = await decryptToken(creds.encryptedRefreshToken, creds.tokenIv);
474→  } catch {
475→    await ctx.runMutation(internal.gmailApi.markCredentialsExpired, {
476→      email: creds.email,
477→    });
478→    return null;
479→  }
480→
481→  try {
482→    const accessToken = await getAccessToken(refreshToken);
483→    await ctx.runMutation(internal.gmailApi.touchCredentials, {
484→      email: creds.email,
485→    });
486→    return { accessToken, email: creds.email };
487→  } catch {
488→    await ctx.runMutation(internal.gmailApi.markCredentialsExpired, {
489→      email: creds.email,
490→    });
491→    return null;
492→  }
493→}
