534→      .query("gmailCredentials")
535→      .withIndex("by_email", (q) => q.eq("email", args.email))
536→      .first();
537→    if (creds) {
538→      await ctx.db.patch(creds._id, {
539→        lastUsedAt: new Date().toISOString(),
540→      });
541→    }
