545→export const findEnrollmentByThread = internalQuery({
546→  args: { threadId: v.string(), email: v.string() },
547→  handler: async (ctx, args) => {
548→    // Find the user by email from watch state
549→    const watchState = await ctx.db
550→      .query("gmailWatchState")
551→      .withIndex("by_email", (q) => q.eq("email", args.email))
552→      .first();
553→    if (!watchState || !watchState.userId) return null;
554→
555→    // Find enrollment with this threadId using index
556→    const enrollment = await ctx.db
557→      .query("sequenceEnrollments")
558→      .withIndex("by_thread", (q) =>
559→        q.eq("userId", watchState.userId).eq("threadId", args.threadId)
560→      )
561→      .first();
562→
563→    if (!enrollment) return null;
564→    if (enrollment.status !== "active" && enrollment.status !== "paused") return null;
565→    return enrollment;
566→  },
