569→export const upsertCredentials = internalMutation({
570→  args: {
571→    userId: v.string(),
572→    email: v.string(),
573→    encryptedRefreshToken: v.string(),
574→    tokenIv: v.string(),
575→    scopes: v.string(),
576→  },
577→  handler: async (ctx, args) => {
578→    const existing = await ctx.db
579→      .query("gmailCredentials")
580→      .withIndex("by_email", (q) => q.eq("email", args.email))
581→      .first();
582→
583→    if (existing) {
584→      await ctx.db.patch(existing._id, {
585→        encryptedRefreshToken: args.encryptedRefreshToken,
586→        tokenIv: args.tokenIv,
587→        scopes: args.scopes,
588→        storedAt: new Date().toISOString(),
589→        status: "active",
590→      });
591→    } else {
592→      await ctx.db.insert("gmailCredentials", {
593→        userId: args.userId,
594→        email: args.email,
595→        encryptedRefreshToken: args.encryptedRefreshToken,
596→        tokenIv: args.tokenIv,
597→        scopes: args.scopes,
598→        storedAt: new Date().toISOString(),
599→        status: "active",
600→      });
601→    }
602→  },
603→});
