605→// ── HTTP endpoint: store credentials (called from CLI during connect) ──
606→
607→export const storeGmailCredentialsHttp = httpAction(async (ctx, request) => {
608→  const authHeader = request.headers.get("Authorization");
609→  if (!authHeader?.startsWith("Bearer ")) {
610→    return new Response(JSON.stringify({ error: "Unauthorized" }), {
611→      status: 401,
612→    });
613→  }
614→  const token = authHeader.slice(7);
615→
616→  const user = await ctx.runQuery(internal.sendApi.findUserByToken, {
617→    token,
618→  });
619→  if (!user) {
620→    return new Response(JSON.stringify({ error: "Invalid token" }), {
621→      status: 401,
622→    });
623→  }
624→
625→  const payload = await request.json();
626→
627→  if (!payload.email || !payload.encryptedRefreshToken || !payload.tokenIv) {
628→    return new Response(
629→      JSON.stringify({ error: "email, encryptedRefreshToken, and tokenIv required" }),
630→      { status: 400, headers: { "Content-Type": "application/json" } }
631→    );
632→  }
633→
634→  await ctx.runMutation(internal.gmailApi.upsertCredentials, {
635→    userId: user._id,
636→    email: payload.email,
637→    encryptedRefreshToken: payload.encryptedRefreshToken,
638→    tokenIv: payload.tokenIv,
639→    scopes: payload.scopes || "gmail.readonly,gmail.send",
640→  });
641→
642→  return new Response(JSON.stringify({ ok: true }), {
643→    status: 200,
644→    headers: { "Content-Type": "application/json" },
645→  });
646→});
