// convex/gmailApi.ts
//
// Gmail API helpers for server-side reply fetching.
// Uses stored refresh token to get access token, then calls history.list
// to find new messages since the last known historyId.

import { v } from "convex/values";
import {
  type ActionCtx,
  internalAction,
  internalMutation,
  internalQuery,
  httpAction,
} from "./_generated/server";
import { internal } from "./_generated/api";
import { decryptToken } from "./crypto";

const GMAIL_TOKEN_URL = "https://oauth2.googleapis.com/token";
const GMAIL_API_BASE = "https://gmail.googleapis.com/gmail/v1/users/me";

// ── Gmail API helpers ───────────────────────────────────────────────

async function getAccessToken(
  refreshToken: string,
  retryCount = 0
): Promise<string> {
  const clientId = process.env.GMAIL_CLIENT_ID;
  const clientSecret = process.env.GMAIL_CLIENT_SECRET;
  if (!clientId || !clientSecret) {
    throw new Error(
      "GMAIL_CLIENT_ID and GMAIL_CLIENT_SECRET env vars required"
    );
  }

  // 10s timeout for token refresh
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), 10000);

  let resp: Response;
  try {
    resp = await fetch(GMAIL_TOKEN_URL, {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: new URLSearchParams({
        client_id: clientId,
        client_secret: clientSecret,
        refresh_token: refreshToken,
        grant_type: "refresh_token",
      }),
      signal: controller.signal,
    });
  } catch (fetchError: unknown) {
    clearTimeout(timeoutId);
    if (fetchError instanceof Error && fetchError.name === "AbortError") {
      // Retry with exponential backoff (max 3 retries)
      if (retryCount < 3) {
        const delay = Math.pow(2, retryCount) * 1000; // 1s, 2s, 4s
        await new Promise((r) => setTimeout(r, delay));
        return getAccessToken(refreshToken, retryCount + 1);
      }
      throw new Error("Token refresh timed out after 3 retries");
    }
    throw fetchError;
  }
  clearTimeout(timeoutId);

  if (!resp.ok) {
    const err = await resp.text();
    // Retry on 5xx errors with exponential backoff
    if (resp.status >= 500 && retryCount < 3) {
      const delay = Math.pow(2, retryCount) * 1000;
      await new Promise((r) => setTimeout(r, delay));
      return getAccessToken(refreshToken, retryCount + 1);
    }
    throw new Error(`Token refresh failed (${resp.status}): ${err}`);
  }

  const data = await resp.json();

  // Validate response contains access_token
  if (!data.access_token) {
    throw new Error("Token refresh response missing access_token field");
  }

  return data.access_token;
}

async function fetchHistoryMessages(
  accessToken: string,
  historyId: string
): Promise<{ messages: Array<{ id: string; threadId: string }>; historyGap: boolean }> {
  const messages: Array<{ id: string; threadId: string }> = [];
  let pageToken: string | undefined;

  do {
    let url = `${GMAIL_API_BASE}/history?startHistoryId=${historyId}&historyTypes=messageAdded&labelId=INBOX`;
    if (pageToken) {
      url += `&pageToken=${pageToken}`;
    }

    // 15s timeout for history.list
    const histController = new AbortController();
    const histTimeout = setTimeout(() => histController.abort(), 15000);

    let resp: Response;
    try {
      resp = await fetch(url, {
        headers: { Authorization: `Bearer ${accessToken}` },
        signal: histController.signal,
      });
    } catch (fetchErr: unknown) {
      clearTimeout(histTimeout);
      if (fetchErr instanceof Error && fetchErr.name === "AbortError") {
        throw new Error("history.list request timed out (15s)");
      }
      throw fetchErr;
    }
    clearTimeout(histTimeout);

    if (!resp.ok) {
      if (resp.status === 404) {
        // historyId too old -- Gmail purged history. Flag so caller can handle.
        console.error(`Gmail history.list 404: historyId ${historyId} is too old. Replies in the gap may be lost.`);
        return { messages: [], historyGap: true };
      }
      throw new Error(`history.list failed (${resp.status})`);
    }

    const data = await resp.json();

    for (const record of data.history || []) {
      for (const msg of record.messagesAdded || []) {
        messages.push({
          id: msg.message.id,
          threadId: msg.message.threadId,
        });
      }
    }

    pageToken = data.nextPageToken;
  } while (pageToken);

  return { messages, historyGap: false };
}

async function fetchMessage(
  accessToken: string,
  messageId: string
): Promise<{
  id: string;
  threadId: string;
  from: string;
  to: string;
  subject: string;
  snippet: string;
  date: string;
  inReplyTo: string;
}> {
  const url = `${GMAIL_API_BASE}/messages/${messageId}?format=metadata&metadataHeaders=From&metadataHeaders=To&metadataHeaders=Subject&metadataHeaders=Date&metadataHeaders=In-Reply-To`;

  // 10s timeout for messages.get
  const msgController = new AbortController();
  const msgTimeout = setTimeout(() => msgController.abort(), 10000);

  let resp: Response;
  try {
    resp = await fetch(url, {
      headers: { Authorization: `Bearer ${accessToken}` },
      signal: msgController.signal,
    });
  } catch (fetchErr: unknown) {
    clearTimeout(msgTimeout);
    if (fetchErr instanceof Error && fetchErr.name === "AbortError") {
      throw new Error(`messages.get timed out for ${messageId} (10s)`);
    }
    throw fetchErr;
  }
  clearTimeout(msgTimeout);

  if (!resp.ok) {
    throw new Error(`messages.get failed (${resp.status})`);
  }

  const data = await resp.json();
  const headers: Record<string, string> = {};
  for (const h of data.payload?.headers || []) {
    headers[h.name.toLowerCase()] = h.value;
  }

  return {
    id: data.id,
    threadId: data.threadId,
    from: headers["from"] || "",
    to: headers["to"] || "",
    subject: headers["subject"] || "",
    snippet: data.snippet || "",
    date: headers["date"] || "",
    inReplyTo: headers["in-reply-to"] || "",
  };
}

function extractEmail(fromHeader: string): string {
  const match = fromHeader.match(/<([^>]+)>/);
  return match ? match[1].toLowerCase() : fromHeader.toLowerCase().trim();
}

// ── Main action: fetch new replies ──────────────────────────────────

type FetchGmailRepliesArgs = {
  email: string;
  historyId: string;
};

type FetchGmailRepliesResult = {
  repliesFound: number;
  error?: string;
};

const fetchGmailRepliesHandler = async (
  ctx: ActionCtx,
  args: FetchGmailRepliesArgs
): Promise<FetchGmailRepliesResult> => {
  // 1. Look up stored credentials
  const creds = await ctx.runQuery(internal.gmailApi.getCredentials, {
    email: args.email,
  });
  if (!creds || creds.status !== "active") {
    console.log(`No active Gmail credentials for ${args.email}`);
    return {
      repliesFound: 0,
      error: creds ? "credentials_" + creds.status : "no_credentials",
    };
  }

  // 2. Decrypt refresh token
  let refreshToken: string;
  try {
    refreshToken = await decryptToken(
      creds.encryptedRefreshToken,
      creds.tokenIv
    );
  } catch (e: unknown) {
    const message = e instanceof Error ? e.message : String(e);
    console.error("Failed to decrypt Gmail token:", message);
    await ctx.runMutation(internal.gmailApi.markCredentialsExpired, {
      email: args.email,
    });
    return { repliesFound: 0, error: "decrypt_failed" };
  }

  // 3. Get access token
  let accessToken: string;
  try {
    accessToken = await getAccessToken(refreshToken);
  } catch (e: unknown) {
    const message = e instanceof Error ? e.message : String(e);
    console.error("Gmail token refresh failed:", message);
    await ctx.runMutation(internal.gmailApi.markCredentialsExpired, {
      email: args.email,
    });
    return { repliesFound: 0, error: "token_refresh_failed" };
  }

  // Update lastUsedAt
  await ctx.runMutation(internal.gmailApi.touchCredentials, {
    email: args.email,
  });

  // 4. Fetch history since last historyId
  const historyResult = await fetchHistoryMessages(accessToken, args.historyId);
  if (historyResult.historyGap) {
    console.error(`History gap detected for ${args.email}. Some replies may have been missed.`);
  }
  const newMessages = historyResult.messages;
  if (newMessages.length === 0) {
    return { repliesFound: 0 };
  }

  // 5. For each new message, check if it's a reply to our outbound
  let repliesFound = 0;
  for (const msg of newMessages) {
    try {
      const message = await fetchMessage(accessToken, msg.id);

      // Skip messages FROM the user's own email (outbound, not inbound)
      if (message.from.toLowerCase().includes(args.email.toLowerCase())) {
        continue;
      }

      // Only process if it's a reply (has In-Reply-To or is in a tracked thread)
      if (!message.inReplyTo && !message.threadId) {
        continue;
      }

      // Check if this thread belongs to one of our enrollments
      const enrollment = await ctx.runQuery(
        internal.gmailApi.findEnrollmentByThread,
        {
          threadId: message.threadId,
          email: args.email,
        }
      );

      if (!enrollment) {
        continue; // Not a reply to our outbound
      }

      // 6. Create reply draft via replyDrafts module
      await ctx.runMutation(internal.replyDrafts.createFromReply, {
        userId: enrollment.userId,
        enrollmentId: enrollment.externalId,
        mailboxId: enrollment.mailboxId,
        threadId: message.threadId,
        messageId: message.id,
        contactEmail: extractEmail(message.from),
        subject: message.subject,
        snippet: message.snippet,
        occurredAt: new Date().toISOString(),
      });

      repliesFound++;
    } catch (e: unknown) {
      const message = e instanceof Error ? e.message : String(e);
      console.error(`Error processing message ${msg.id}:`, message);
    }
  }

  return { repliesFound };
};

export const fetchGmailReplies = internalAction({
  args: {
    email: v.string(),
    historyId: v.string(),
  },
  handler: fetchGmailRepliesHandler,
});

// ── Gmail send (direct, no Unipile) ─────────────────────────────────

function buildRfc2822Message(
  from: string,
  to: string,
  subject: string,
  body: string,
  inReplyTo?: string
): string {
  const boundary = `boundary_${Date.now()}_${Math.random().toString(36).slice(2)}`;
  const lines: string[] = [
    `From: ${from}`,
    `To: ${to}`,
    `Subject: ${subject}`,
    `MIME-Version: 1.0`,
    `Content-Type: multipart/alternative; boundary="${boundary}"`,
  ];

  if (inReplyTo) {
    lines.push(`In-Reply-To: ${inReplyTo}`);
    lines.push(`References: ${inReplyTo}`);
  }

  lines.push(""); // Empty line before body
  lines.push(`--${boundary}`);
  lines.push("Content-Type: text/plain; charset=UTF-8");
  lines.push("");
  lines.push(body);
  lines.push(`--${boundary}`);
  lines.push("Content-Type: text/html; charset=UTF-8");
  lines.push("");
  lines.push(body.replace(/\n/g, "<br>"));
  lines.push(`--${boundary}--`);

  return lines.join("\r\n");
}

function base64UrlEncode(str: string): string {
  const encoder = new TextEncoder();
  const bytes = encoder.encode(str);
  let binary = "";
  for (const byte of bytes) {
    binary += String.fromCharCode(byte);
  }
  return btoa(binary)
    .replace(/\+/g, "-")
    .replace(/\//g, "_")
    .replace(/=+$/, "");
}

export async function callGmailSend(args: {
  accessToken: string;
  from: string;
  to: string;
  subject: string;
  body: string;
  threadId?: string;
  inReplyTo?: string;
}): Promise<
  | { ok: true; messageId: string; threadId: string }
  | { ok: false; error: string; authError: boolean }
> {
  const raw = buildRfc2822Message(
    args.from,
    args.to,
    args.subject,
    args.body,
    args.inReplyTo
  );

  const payload: Record<string, string> = {
    raw: base64UrlEncode(raw),
  };

  if (args.threadId) {
    payload.threadId = args.threadId;
  }

  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), 30000);

  let resp: Response;
  try {
    resp = await fetch(`${GMAIL_API_BASE}/messages/send`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${args.accessToken}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify(payload),
      signal: controller.signal,
    });
  } catch (fetchError: any) {
    clearTimeout(timeoutId);
    if (fetchError.name === "AbortError") {
      return { ok: false, error: "Gmail send timed out (30s)", authError: false };
    }
    return { ok: false, error: `Gmail send error: ${fetchError.message}`, authError: false };
  }
  clearTimeout(timeoutId);

  if (!resp.ok) {
    const errorText = await resp.text();
    const isAuth = resp.status === 401 || resp.status === 403;
    return {
      ok: false,
      error: isAuth
        ? `Gmail auth error: ${errorText}`
        : `Gmail API error ${resp.status}: ${errorText}`,
      authError: isAuth,
    };
  }

  const result = await resp.json();
  return {
    ok: true,
    messageId: result.id || "",
    threadId: result.threadId || "",
  };
}

// Get an access token for a user by looking up their stored Gmail credentials.
// Used by the Slack approve-to-send flow and any server-side send operation.
export async function getAccessTokenForUser(
  ctx: ActionCtx,
  userId: string
): Promise<{ accessToken: string; email: string } | null> {
  const creds = await ctx.runQuery(internal.gmailApi.getCredentialsByUser, {
    userId,
  });
  if (!creds || creds.status !== "active") return null;

  let refreshToken: string;
  try {
    refreshToken = await decryptToken(creds.encryptedRefreshToken, creds.tokenIv);
  } catch {
    await ctx.runMutation(internal.gmailApi.markCredentialsExpired, {
      email: creds.email,
    });
    return null;
  }

  try {
    const accessToken = await getAccessToken(refreshToken);
    await ctx.runMutation(internal.gmailApi.touchCredentials, {
      email: creds.email,
    });
    return { accessToken, email: creds.email };
  } catch {
    await ctx.runMutation(internal.gmailApi.markCredentialsExpired, {
      email: creds.email,
    });
    return null;
  }
}

