  handler: async (ctx, args) => {
    return await ctx.db
      .query("gmailCredentials")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();
  },
});

export const markCredentialsExpired = internalMutation({
  args: { email: v.string() },
  handler: async (ctx, args) => {
    const creds = await ctx.db
      .query("gmailCredentials")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();
    if (creds) {
      await ctx.db.patch(creds._id, { status: "expired" });
    }
  },
});

export const touchCredentials = internalMutation({
  args: { email: v.string() },
  handler: async (ctx, args) => {
    const creds = await ctx.db
      .query("gmailCredentials")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();
    if (creds) {
      await ctx.db.patch(creds._id, {
        lastUsedAt: new Date().toISOString(),
      });
    }
  },
});

export const findEnrollmentByThread = internalQuery({
  args: { threadId: v.string(), email: v.string() },
  handler: async (ctx, args) => {
    // Find the user by email from watch state
    const watchState = await ctx.db
      .query("gmailWatchState")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();
    if (!watchState || !watchState.userId) return null;

    // Find enrollment with this threadId using index
    const enrollment = await ctx.db
      .query("sequenceEnrollments")
      .withIndex("by_thread", (q) =>
        q.eq("userId", watchState.userId).eq("threadId", args.threadId)
      )
      .first();

    if (!enrollment) return null;
    if (enrollment.status !== "active" && enrollment.status !== "paused") return null;
    return enrollment;
  },
});

export const upsertCredentials = internalMutation({
  args: {
    userId: v.string(),
    email: v.string(),
    encryptedRefreshToken: v.string(),
    tokenIv: v.string(),
    scopes: v.string(),
  },
  handler: async (ctx, args) => {
    const existing = await ctx.db
      .query("gmailCredentials")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();

    if (existing) {
      await ctx.db.patch(existing._id, {
        encryptedRefreshToken: args.encryptedRefreshToken,
        tokenIv: args.tokenIv,
        scopes: args.scopes,
        storedAt: new Date().toISOString(),
        status: "active",
      });
    } else {
      await ctx.db.insert("gmailCredentials", {
        userId: args.userId,
        email: args.email,
        encryptedRefreshToken: args.encryptedRefreshToken,
        tokenIv: args.tokenIv,
        scopes: args.scopes,
        storedAt: new Date().toISOString(),
        status: "active",
      });
    }
  },
});

