// ── Send approved reply via existing Unipile path ───────────────────

async function sendApprovedReply(
  ctx: ActionCtx,
  draftId: Id<"replyDrafts">,
  sendData: {
    userId: string;
    contactEmail: string;
    threadId: string;
    subject: string;
    body: string;
  }
): Promise<boolean> {
  // Prefer direct Gmail API (no Unipile dependency, no cost)
  const gmailAuth = await getAccessTokenForUser(ctx, sendData.userId);
  if (gmailAuth) {
    const result = await callGmailSend({
      accessToken: gmailAuth.accessToken,
      from: gmailAuth.email,
      to: sendData.contactEmail,
      subject: sendData.subject,
      body: sendData.body,
      threadId: sendData.threadId,
    });

    if (result.ok) {
      await ctx.runMutation(internal.replyDrafts.markDraftSent, { draftId });
      return true;
    }

    // If Gmail auth error, fall through to Unipile
    if (!result.authError) {
      console.error("Gmail send failed:", result.error);
      return false;
    }
    console.warn("Gmail auth failed, falling back to Unipile");
  }

  // Fallback: Unipile (if Gmail credentials unavailable or auth expired)
  const unipileAccount = await ctx.runQuery(
    internal.sendApi.findUnipileAccount,
    { userId: sendData.userId, provider: "GOOGLE" }
  );

  if (!unipileAccount || unipileAccount.status !== "connected") {
    console.error("No send path available: Gmail credentials expired and Unipile not connected");
    return false;
  }

  const enrollment = await ctx.runQuery(
    internal.slack.findEnrollmentByThread,
    { userId: sendData.userId, threadId: sendData.threadId }
  );

  const sendResult = await callUnipileSend({
    accountId: unipileAccount.unipileAccountId,
    to: sendData.contactEmail,
    subject: sendData.subject,
    body: sendData.body,
    replyTo: enrollment?.unipileThreadProviderId || undefined,
  });

  if (sendResult.ok) {
    await ctx.runMutation(internal.replyDrafts.markDraftSent, { draftId });
    return true;
  }

  console.error("Unipile send failed:", sendResult.error);
  return false;
}

