// POST /api/disconnect-provider — best-effort server-side disconnect
export const disconnectProvider = httpAction(async (ctx, request) => {
  try {
    const auth = await authenticateRequest(ctx, request);
    if (auth.error) return auth.error;
    const user = auth.user!;

    const payload = await request.json().catch(() => ({}));
    const provider = String(payload.provider || "").toUpperCase();
    if (!provider) {
      return jsonResponse({ error: "Missing provider" }, 400);
    }

    if (provider === "SLACK") {
      await ctx.runMutation((internal as any).slack.revokeSlackConnection, {
        userId: user._id,
      });
      return jsonResponse({ ok: true });
    }

    if (provider === "HUBSPOT") {
      await ctx.runMutation(internal.connect.disconnectHubSpotConnection, {
        userId: user._id,
      });
      return jsonResponse({ ok: true });
    }

    if (provider === "GOOGLE" || provider === "LINKEDIN") {
      const accounts = await ctx.runQuery(internal.connect.findAllUnipileAccounts, {
        userId: user._id,
        provider,
      });

      for (const account of accounts) {
        await ctx.runMutation(internal.webhook.updateAccountStatus, {
          userId: user._id,
          unipileAccountId: account.unipileAccountId,
          status: "disconnected",
        });
      }

      return jsonResponse({ ok: true });
    }

    return jsonResponse({ error: `Unsupported provider: ${provider}` }, 400);
  } catch (error: any) {
    console.error("disconnect-provider error:", error);
    return jsonResponse({ error: error.message }, 500);
  }
});

// POST /api/sync-emails — CLI fetches emails from Convex (backfilled from Unipile)
export const syncEmails = httpAction(async (ctx, request) => {
  try {
    const auth = await authenticateRequest(ctx, request);
    if (auth.error) return auth.error;
    const user = auth.user!;

    const payload = await request.json().catch(() => ({}));
    const afterVersion = payload.afterVersion ?? 0;

    const emails = await ctx.runQuery(internal.connect.listEmailsAfterVersion, {
      userId: user._id,
      afterVersion,
    });

    return jsonResponse({ emails, count: emails.length });
  } catch (error: any) {
    return jsonResponse({ error: error.message }, 500);
  }
});

