import { cronJobs } from "convex/server";
import { internal } from "./_generated/api";

const crons = cronJobs();

// Check for due tasks every 5 minutes.
// Overlap protection: the dispatcher's claimTask mutation uses atomic status
// checks (only claims tasks with sendStatus "pending"), so even if two cron
// invocations overlap, a task will only be processed once.
crons.interval(
  "check due sequence tasks",
  { minutes: 5 },
  internal.dispatcher.checkDueTasks,
);

// Expire stale reply drafts (24h TTL)
crons.interval(
  "expire stale reply drafts",
  { hours: 1 },
  internal.replyDrafts.expireStaleDrafts,
);

// Detect stale deals (no activity for 30+ days after reply)
crons.interval(
  "detect stale deals",
  { hours: 24 },
  internal.outcomeDetection.detectStaleDeals,
);

export default crons;

