// POST /api/connect-hubspot — returns HubSpot OAuth URL for CRM install
export const connectHubSpot = httpAction(async (ctx, request) => {
  try {
    const auth = await authenticateRequest(ctx, request);
    if (auth.error) return auth.error;
    const user = auth.user!;

    const existing = await ctx.runQuery(internal.connect.findHubSpotConnection, {
      userId: user._id,
    });
    if (existing && existing.status === "active") {
      return jsonResponse({
        already_connected: true,
        name: formatHubSpotConnectionName(existing),
      });
    }

    const { clientId } = getHubSpotConfig();
    const redirectUri = hubSpotRedirectURL(new URL(request.url).origin);
    const state = generateId("oauth");

    await ctx.runMutation(internal.connect.createOAuthConnectState, {
      state,
      userId: user._id,
      provider: "HUBSPOT",
      redirectUri,
    });

    const params = new URLSearchParams({
      client_id: clientId,
      redirect_uri: redirectUri,
      scope: HUBSPOT_SCOPES.join(" "),
      state,
    });

    return jsonResponse({
      url: `${HUBSPOT_AUTHORIZE_URL}?${params.toString()}`,
    });
  } catch (error: any) {
    console.error("connect-hubspot error:", error);
    return jsonResponse({ error: error.message }, 500);
  }
});

// POST /api/connect-slack — returns Slack OAuth URL for workspace install
export const connectSlack = httpAction(async (ctx, request) => {
  try {
    const auth = await authenticateRequest(ctx, request);
    if (auth.error) return auth.error;
    const user = auth.user!;

    const existing = await ctx.runQuery((internal as any).slack.getSlackConnection, {
      userId: user._id,
    });
    if (existing && existing.status === "active") {
      return jsonResponse({
        already_connected: true,
        name: formatSlackConnectionName(
          existing.teamName,
          existing.teamId,
          existing.channelName,
          existing.channelId
        ),
      });
    }

    const { clientId, clientSecret, convexSiteUrl } = getSlackConfig();
    const state = await encodeSlackState(user._id, clientSecret);

    const params = new URLSearchParams({
      client_id: clientId,
      scope: SLACK_SCOPES.join(","),
      redirect_uri: slackRedirectURL(convexSiteUrl),
      state,
    });

    return jsonResponse({
      url: `https://slack.com/oauth/v2/authorize?${params.toString()}`,
    });
  } catch (error: any) {
    console.error("connect-slack error:", error);
    return jsonResponse({ error: error.message }, 500);
  }
});

