package conn

import (
	"fmt"
	"os"
	"path/filepath"
	"time"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/cmd/cmdutil"
	"github.com/usenurge/nurgesh/internal/account"
	"github.com/usenurge/nurgesh/internal/connector"
	"github.com/usenurge/nurgesh/internal/project"
	"github.com/usenurge/nurgesh/internal/util"
)

var forceConnect bool

func init() {
	connectCmd.Flags().BoolVar(&forceConnect, "force", false, "Overwrite existing connection")
}

func checkExistingConnection(id string) (bool, string) {
	if !project.IsNurgeProject(".") {
		return false, ""
	}
	cfg, err := project.Load()
	if err != nil {
		return false, ""
	}
	cs, ok := cfg.Connectors[id]
	if !ok || !cs.Connected {
		return false, ""
	}
	return true, cs.Account
}

const connectLockTTL = 5 * time.Minute

func acquireConnectLock(id string) (func(), error) {
	lockDir := fmt.Sprintf(".nurge/connectors/%s", id)
	if err := os.MkdirAll(lockDir, 0700); err != nil {
		return nil, err
	}
	lockPath := filepath.Join(lockDir, ".connecting")
	f, err := os.OpenFile(lockPath, os.O_CREATE|os.O_EXCL|os.O_WRONLY, 0600)
	if err != nil {
		if os.IsExist(err) {
			// TTL-based stale lock detection: if lock file is older than 5 minutes, remove it and proceed
			info, statErr := os.Stat(lockPath)
			if statErr == nil && time.Since(info.ModTime()) > connectLockTTL {
				fmt.Fprintf(os.Stderr, "  Removing stale lock file for %s (older than %s)\n", id, connectLockTTL)
				os.Remove(lockPath)
				// Retry creating the lock
				f, err = os.OpenFile(lockPath, os.O_CREATE|os.O_EXCL|os.O_WRONLY, 0600)
				if err != nil {
					return nil, fmt.Errorf("%s connection lock could not be acquired after stale removal: %w", id, err)
				}
			} else {
				return nil, fmt.Errorf("%s connection already in progress (remove %s if stale)", id, lockPath)
			}
		} else {
			return nil, err
		}
	}
	fmt.Fprintf(f, "%d", os.Getpid())
	f.Close()
	return func() { os.Remove(lockPath) }, nil
}

var connectCmd = &cobra.Command{
	Use:   "connect <service>",
	Short: "Connect a service (run `nurge connectors available` to see options)",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		id := args[0]
		if connected, existingAccount := checkExistingConnection(id); connected {
			if !forceConnect {
				fmt.Fprintf(os.Stderr, "  %s is already connected (%s)\n  Use --force to reconnect\n", id, existingAccount)
				return fmt.Errorf("%s already connected, use --force to overwrite", id)

