```typescript
// POST /api/connect-gmail — check Gmail credentials status
// Gmail OAuth is handled locally by the CLI (YAML connector definition).
// The CLI pushes encrypted refresh tokens to Convex via /api/store-gmail-credentials.
// This endpoint reports current status for the CLI polling flow.
export const connectGmail = httpAction(async (ctx, request) => {
  try {
    const auth = await authenticateRequest(ctx, request);
    if (auth.error) return auth.error;
    const user = auth.user!;

    const creds = await ctx.runQuery(internal.gmailApi.getCredentialsByUser, {
      userId: user._id,
    });

    if (creds && creds.status === "active") {
      return jsonResponse({
        already_connected: true,
        email: creds.email,
      });
    }

    // No server-side URL needed — CLI handles OAuth locally
    // Return instructions for the CLI
    return jsonResponse({
      local_oauth: true,
      message: "Gmail OAuth is handled locally. The CLI will push credentials after auth.",
    });
  } catch (error: any) {
    console.error("connect-gmail error:", error);
    return jsonResponse({ error: error.message }, 500);
  }
});
```

