```go
func connectGmail() error {
	registry, err := connector.LoadRegistry(projectLocalDefs)
	if err != nil {
		return fmt.Errorf("loading connector registry: %w", err)
	}
	var found *connector.ConnectorDef
	for i := range registry {
		if registry[i].ID == "gmail" {
			found = &registry[i]
			break
		}
	}
	if found == nil {
		return fmt.Errorf("gmail connector definition not found")
	}

	c := connector.NewFromDef(*found, "")
	result, err := c.Connect(nil)
	if err != nil {
		return fmt.Errorf("connecting gmail: %w", err)
	}

	if project.IsNurgeProject(".") {
		_ = project.SetConnector("gmail", "email", result.Account)
	}
	fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Gmail connected (%s)\n", result.Account)
	return nil
}
```

